window.SECTION_MAP["cslb-law"] = {1:"Org & Licensing",2:"Business Finances",3:"Employment",4:"Insurance & Liens",5:"Contracts",6:"Public Works",7:"Safety"};
window.COURSE_REGISTRY["cslb-law"] = [
  {"id":1,"sec":"Org & Licensing","secNum":1,"block":1,"q":"In California, a contractor's license is generally required when the combined cost of labor and materials on a project is at least:","opts":["$200","$500","$1,000","$2,500"],"correct":1,"re":"Work valued at $500 or more (labor + materials) requires a license; below that is the 'minor work' exemption — but the job can't be split to dodge the limit."},
  {"id":2,"sec":"Org & Licensing","secNum":1,"block":1,"q":"The minimum age to apply for a contractor's license in California is:","opts":["16","18","21","25"],"correct":1,"re":"Applicants must be at least 18 years old."},
  {"id":3,"sec":"Org & Licensing","secNum":1,"block":1,"q":"A contractor's bond required of most active California licensees is in the amount of:","opts":["$12,500","$15,000","$25,000","$100,000"],"correct":2,"re":"The contractor's bond is $25,000 (raised from $15,000 effective Jan 1, 2023)."},
  {"id":4,"sec":"Org & Licensing","secNum":1,"block":1,"q":"How often must a California contractor's license be renewed?","opts":["Every year","Every 2 years","Every 3 years","Every 5 years"],"correct":1,"re":"Active and inactive licenses renew every two years."},
  {"id":5,"sec":"Org & Licensing","secNum":1,"block":1,"q":"A licensee must notify the CSLB of a change of business address within:","opts":["10 days","30 days","90 days","6 months"],"correct":2,"re":"Address changes must be reported to the Board within 90 days."},
  {"id":6,"sec":"Org & Licensing","secNum":1,"block":1,"q":"The person who takes and passes the trade and law exams to qualify a license is the:","opts":["Registered agent","Qualifying individual","Bond guarantor","Responsible employee"],"correct":1,"re":"The qualifying individual (RMO or RME) holds the trade knowledge that qualifies the license."},
  {"id":7,"sec":"Org & Licensing","secNum":1,"block":1,"q":"An RME (Responsible Managing Employee) must be employed by the licensee at least:","opts":["8 hours/week","16 hours/week or 60% of the business's hours","32 hours/week","Full-time only"],"correct":1,"re":"An RME must work at least 32 hours or 60% of the business's total operating hours per week — whichever is less."},
  {"id":8,"sec":"Org & Licensing","secNum":1,"block":1,"q":"Which business form makes owners personally liable for all business debts?","opts":["Corporation","Limited liability company","Sole proprietorship","Limited partnership (limited partners)"],"correct":2,"re":"A sole proprietor is personally liable for all debts and obligations of the business."},
  {"id":9,"sec":"Org & Licensing","secNum":1,"block":1,"q":"A 'Bond of Qualifying Individual' is generally required when the qualifier is:","opts":["A sole owner","An RMO owning 10% or more of the corporation","An RME or an RMO owning less than 10%","Any qualifier, always"],"correct":2,"re":"The qualifier's bond ($25,000) is required for an RME, or an RMO who owns less than 10% of the voting stock."},
  {"id":10,"sec":"Org & Licensing","secNum":1,"block":1,"q":"Contracting without a license when one is required is generally a:","opts":["Infraction with no penalty","Misdemeanor","Felony on first offense","Civil matter only"],"correct":1,"re":"Unlicensed contracting is a misdemeanor; penalties escalate on repeat offenses."},
  {"id":11,"sec":"Org & Licensing","secNum":1,"block":1,"q":"An unlicensed contractor who sues to collect payment for work requiring a license will generally:","opts":["Win full payment","Recover only materials cost","Be barred from collecting and may have to refund paid amounts","Recover 50%"],"correct":2,"re":"B&P Code §7031 bars unlicensed contractors from suing for compensation and lets clients recover what they already paid."},
  {"id":12,"sec":"Org & Licensing","secNum":1,"block":1,"q":"When the qualifying individual disassociates from a license, the licensee must notify CSLB within:","opts":["10 days","30 days","90 days","1 year"],"correct":2,"re":"Disassociation of the qualifier must be reported within 90 days, or the license may be suspended."},
  {"id":13,"sec":"Org & Licensing","secNum":1,"block":1,"q":"A joint venture license:","opts":["Needs no separate registration","Combines two or more licensees and must itself be licensed","Is only for public works","Replaces each partner's individual license"],"correct":1,"re":"A joint venture of licensed contractors must obtain its own joint venture license number."},
  {"id":14,"sec":"Business Finances","secNum":2,"block":1,"q":"In a basic accounting equation, Assets equal:","opts":["Liabilities − Equity","Liabilities + Owner's Equity","Revenue − Expenses","Equity − Liabilities"],"correct":1,"re":"Assets = Liabilities + Owner's Equity is the fundamental accounting equation."},
  {"id":15,"sec":"Business Finances","secNum":2,"block":1,"q":"Money owed TO the business by customers is recorded as:","opts":["Accounts payable","Accounts receivable","Retained earnings","Owner's draw"],"correct":1,"re":"Accounts receivable is money customers owe the business."},
  {"id":16,"sec":"Business Finances","secNum":2,"block":1,"q":"Money the business OWES to suppliers is:","opts":["Accounts receivable","Accounts payable","Gross profit","Net worth"],"correct":1,"re":"Accounts payable is what the business owes others."},
  {"id":17,"sec":"Business Finances","secNum":2,"block":1,"q":"Gross profit is calculated as:","opts":["Revenue − all expenses","Revenue − cost of goods sold","Assets − liabilities","Net income + taxes"],"correct":1,"re":"Gross profit = revenue − cost of goods sold, before overhead."},
  {"id":18,"sec":"Business Finances","secNum":2,"block":1,"q":"Overhead costs are best described as:","opts":["Direct labor on a job","Materials for a specific job","Ongoing costs not tied to one job (rent, insurance, office)","Subcontractor invoices"],"correct":2,"re":"Overhead is indirect cost of running the business, not chargeable to a single job."},
  {"id":19,"sec":"Business Finances","secNum":2,"block":1,"q":"A markup of 25% on a $4,000 job cost produces a selling price of:","opts":["$4,250","$4,500","$5,000","$5,333"],"correct":2,"re":"$4,000 × 1.25 = $5,000. (Markup is on cost, not on price.)"},
  {"id":20,"sec":"Business Finances","secNum":2,"block":1,"q":"The accounting method that records income when earned and expenses when incurred (not when cash moves) is:","opts":["Cash basis","Accrual basis","Completed-contract only","Petty cash"],"correct":1,"re":"Accrual basis records revenue/expense when earned/incurred, regardless of cash timing."},
  {"id":21,"sec":"Business Finances","secNum":2,"block":1,"q":"A 'current ratio' measures a company's ability to:","opts":["Grow long-term","Pay short-term obligations","Increase markup","Reduce taxes"],"correct":1,"re":"Current ratio = current assets ÷ current liabilities; it gauges short-term liquidity."},
  {"id":22,"sec":"Business Finances","secNum":2,"block":1,"q":"Depreciation on a work truck is:","opts":["A cash payment each year","An allocation of an asset's cost over its useful life","A type of insurance","A liability"],"correct":1,"re":"Depreciation spreads a capital asset's cost across the years it is used."},
  {"id":23,"sec":"Business Finances","secNum":2,"block":1,"q":"Working capital equals:","opts":["Total assets","Current assets − current liabilities","Revenue − overhead","Equity + debt"],"correct":1,"re":"Working capital = current assets − current liabilities."},
  {"id":24,"sec":"Business Finances","secNum":2,"block":1,"q":"Which document summarizes income and expenses over a period to show profit or loss?","opts":["Balance sheet","Income (profit & loss) statement","Bond schedule","Lien waiver"],"correct":1,"re":"The income statement (P&L) shows revenue, expenses, and resulting profit/loss for a period."},
  {"id":25,"sec":"Business Finances","secNum":2,"block":1,"q":"Federal income tax withheld from employee paychecks is:","opts":["The employer's expense","Held in trust and remitted to the IRS","Optional for small firms","Refunded to the employer"],"correct":1,"re":"Withholding is the employee's money held in trust by the employer and paid to the IRS."},
  {"id":26,"sec":"Business Finances","secNum":2,"block":1,"q":"FICA taxes fund:","opts":["State disability only","Social Security and Medicare","Unemployment only","Workers' compensation"],"correct":1,"re":"FICA covers Social Security and Medicare, split between employer and employee."},
  {"id":27,"sec":"Business Finances","secNum":2,"block":1,"q":"A cash-flow problem most directly means the business:","opts":["Is unprofitable","Lacks cash to meet obligations when due","Has too many assets","Pays too little tax"],"correct":1,"re":"Cash-flow trouble is a timing problem — not enough cash on hand when bills come due, even if profitable."},
  {"id":28,"sec":"Employment","secNum":3,"block":1,"q":"California workers' compensation insurance is required when a business has:","opts":["10 or more employees","5 or more employees","Any employees at all","Only union employees"],"correct":2,"re":"Any employer with even one employee must carry workers' comp."},
  {"id":29,"sec":"Employment","secNum":3,"block":1,"q":"A licensee with no employees may file with CSLB a:","opts":["Performance bond","Workers' comp exemption certificate","Lien release","Notice of completion"],"correct":1,"re":"A licensee with no employees can certify an exemption from workers' comp."},
  {"id":30,"sec":"Employment","secNum":3,"block":1,"q":"In California, daily overtime (1.5×) generally begins after:","opts":["6 hours","8 hours","10 hours","12 hours"],"correct":1,"re":"Overtime at 1.5× starts after 8 hours in a day (and after 40 in a week)."},
  {"id":31,"sec":"Employment","secNum":3,"block":1,"q":"Double-time pay (2×) in California is generally required after:","opts":["8 hours/day","10 hours/day","12 hours/day","16 hours/day"],"correct":2,"re":"Double time applies after 12 hours in a workday (and after 8 hours on the 7th consecutive day)."},
  {"id":32,"sec":"Employment","secNum":3,"block":1,"q":"An employee who is fired must receive their final paycheck:","opts":["Within 72 hours","On the next payday","Immediately at termination","Within 30 days"],"correct":2,"re":"A discharged employee's final wages are due immediately at the time of termination."},
  {"id":33,"sec":"Employment","secNum":3,"block":1,"q":"An employee who quits without notice must be paid final wages within:","opts":["Immediately","24 hours","72 hours","The next payday"],"correct":2,"re":"For a quit without notice, final wages are due within 72 hours."},
  {"id":34,"sec":"Employment","secNum":3,"block":1,"q":"The federal form used to verify a new employee's eligibility to work is:","opts":["W-2","W-4","I-9","1099"],"correct":2,"re":"Form I-9 verifies identity and work authorization for each new hire."},
  {"id":35,"sec":"Employment","secNum":3,"block":1,"q":"An employee completes which form to set income-tax withholding?","opts":["I-9","W-4","W-2","1099-NEC"],"correct":1,"re":"The W-4 tells the employer how much income tax to withhold."},
  {"id":36,"sec":"Employment","secNum":3,"block":1,"q":"A worker paid via Form 1099-NEC is generally treated as a(n):","opts":["Employee","Independent contractor","Apprentice","Partner"],"correct":1,"re":"A 1099-NEC reports payments to an independent contractor, not an employee."},
  {"id":37,"sec":"Employment","secNum":3,"block":1,"q":"California's 'ABC test' (AB 5) is used to determine whether a worker is:","opts":["Bondable","An employee or an independent contractor","Eligible for overtime exemption","A public works worker"],"correct":1,"re":"The ABC test presumes a worker is an employee unless all three prongs (A, B, C) are met."},
  {"id":38,"sec":"Employment","secNum":3,"block":1,"q":"New hires must be reported to the EDD New Employee Registry within:","opts":["20 days of the start-of-work date","60 days","90 days","Before the first paycheck only"],"correct":0,"re":"Employers report new hires to the EDD within 20 days."},
  {"id":39,"sec":"Employment","secNum":3,"block":1,"q":"State Disability Insurance (SDI) in California is:","opts":["Paid entirely by the employer","Deducted from employee wages","The same as workers' comp","Optional"],"correct":1,"re":"SDI is funded by a deduction from employee wages, administered by the EDD."},
  {"id":40,"sec":"Employment","secNum":3,"block":1,"q":"Federal and state unemployment insurance (FUTA/SUI) is generally:","opts":["Withheld from employees","An employer-paid tax","Paid by the contractor's client","Not required in California"],"correct":1,"re":"Unemployment insurance is an employer cost, not withheld from workers' pay."},
  {"id":41,"sec":"Employment","secNum":3,"block":1,"q":"Required meal break for a nonexempt employee working over 5 hours is:","opts":["10 minutes","20 minutes","30 minutes unpaid","60 minutes"],"correct":2,"re":"A 30-minute unpaid meal period is required for shifts over 5 hours."},
  {"id":42,"sec":"Employment","secNum":3,"block":1,"q":"A paid rest break of 10 minutes is generally required for each:","opts":["2 hours worked","4 hours (or major fraction) worked","6 hours worked","8 hours worked"],"correct":1,"re":"Ten-minute paid rest breaks are required per 4 hours (or major fraction) worked."},
  {"id":43,"sec":"Employment","secNum":3,"block":1,"q":"Misclassifying an employee as an independent contractor can result in:","opts":["No consequences","Back taxes, penalties, and liability","A bonus from EDD","Automatic license upgrade"],"correct":1,"re":"Willful misclassification exposes the employer to back taxes, penalties, and wage liability."},
  {"id":44,"sec":"Employment","secNum":3,"block":1,"q":"The agency that enforces California wage-and-hour laws is the:","opts":["CSLB","DLSE (Labor Commissioner)","EPA","DIR Apprenticeship only"],"correct":1,"re":"The DLSE / Labor Commissioner enforces wage-and-hour law."},
  {"id":45,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"General liability insurance for a contractor primarily covers:","opts":["Employee injuries","Damage or injury the contractor causes to others/property","The contractor's own tools","Tax penalties"],"correct":1,"re":"GL covers third-party bodily injury and property damage caused by the contractor's work."},
  {"id":46,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"Workers' compensation insurance covers:","opts":["Damage to a customer's house","On-the-job injuries to the contractor's employees","Defective materials","Contract breach"],"correct":1,"re":"Workers' comp pays for employees' job-related injuries and illnesses."},
  {"id":47,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"A preliminary 20-day notice must generally be served within 20 days of:","opts":["Signing the contract","First furnishing labor or materials","Project completion","Recording a lien"],"correct":1,"re":"The preliminary notice is served within 20 days of first furnishing labor/materials to preserve lien rights."},
  {"id":48,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"A mechanics lien is a remedy that attaches to:","opts":["The contractor's license","The improved real property","The owner's bank account","The building permit"],"correct":1,"re":"A mechanics lien attaches to the real property that was improved."},
  {"id":49,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"If no Notice of Completion is recorded, a direct (prime) contractor must record a mechanics lien within:","opts":["30 days of completion","60 days of completion","90 days of completion","1 year of completion"],"correct":2,"re":"With no NOC, the direct contractor has 90 days after completion to record a lien."},
  {"id":50,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"After recording a mechanics lien, suit to foreclose it must be filed within:","opts":["30 days","60 days","90 days","6 months"],"correct":2,"re":"A foreclosure action on the lien must be filed within 90 days of recording, or the lien expires."},
  {"id":51,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"A Notice of Completion is recorded by the owner within how many days of completion?","opts":["5 days","10 days","15 days","30 days"],"correct":2,"re":"The owner records the NOC within 15 days of completion to shorten lien-filing windows."},
  {"id":52,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"A bond that protects the owner if the contractor fails to complete the work is a:","opts":["Bid bond","Performance bond","Payment bond","License bond"],"correct":1,"re":"A performance bond guarantees completion of the contract."},
  {"id":53,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"A payment bond guarantees that:","opts":["The owner gets a refund","Subcontractors and suppliers are paid","The contractor completes on time","The bid is honored"],"correct":1,"re":"A payment (labor & material) bond assures subs and suppliers get paid."},
  {"id":54,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"A document by which a claimant gives up lien rights after payment is a:","opts":["Stop notice","Lien release / waiver","Preliminary notice","Notice of cessation"],"correct":1,"re":"A lien waiver/release relinquishes lien rights, typically in exchange for payment."},
  {"id":55,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"To remove a recorded lien from title, an owner may record a surety bond (release bond) for:","opts":["50% of the lien","100% of the lien","125% of the lien","200% of the lien"],"correct":2,"re":"A lien release bond is 125% of the lien amount."},
  {"id":56,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"On private works, the modern equivalent of the old 'stop notice' is the:","opts":["Stop payment notice","Cease-and-desist","Notice of nonresponsibility","Mechanics lien"],"correct":0,"re":"The 'stop payment notice' lets a claimant reach undisbursed construction funds."},
  {"id":57,"sec":"Contracts","secNum":5,"block":1,"q":"For a contract to be valid, all of the following are required EXCEPT:","opts":["Mutual consent (offer & acceptance)","Consideration","Lawful object","A notary's seal"],"correct":3,"re":"Most contracts need consent, consideration, capacity, and a lawful object — not a notary."},
  {"id":58,"sec":"Contracts","secNum":5,"block":1,"q":"A home improvement contract in California must be in writing when it exceeds:","opts":["$200","$500","$1,000","$5,000"],"correct":1,"re":"Home improvement contracts over $500 must be in writing and signed before work begins."},
  {"id":59,"sec":"Contracts","secNum":5,"block":1,"q":"The maximum down payment on a home improvement contract is the lesser of $1,000 or:","opts":["5% of the contract","10% of the contract","20% of the contract","25% of the contract"],"correct":1,"re":"Down payment is capped at the lesser of $1,000 or 10% of the contract price."},
  {"id":60,"sec":"Contracts","secNum":5,"block":1,"q":"A buyer's three-day right to cancel typically applies to:","opts":["All contracts","Home solicitation (door-to-door) contracts","Public works only","Verbal contracts"],"correct":1,"re":"Home-solicitation sales carry a 3-day right of rescission."},
  {"id":61,"sec":"Contracts","secNum":5,"block":1,"q":"A change order is best described as:","opts":["A new license","A written modification to the original contract","A type of bond","A lien release"],"correct":1,"re":"A change order documents agreed changes to scope, price, or time — best in writing."},
  {"id":62,"sec":"Contracts","secNum":5,"block":1,"q":"A contract that cannot legally be enforced by either party is:","opts":["Voidable","Void","Express","Implied"],"correct":1,"re":"A void contract (e.g., for an illegal purpose) has no legal effect from the start."},
  {"id":63,"sec":"Contracts","secNum":5,"block":1,"q":"A voidable contract is one that:","opts":["Is illegal","One party may choose to affirm or cancel","Needs no consideration","Is always written"],"correct":1,"re":"A voidable contract is valid until the party with the right elects to rescind (e.g., a minor's contract)."},
  {"id":64,"sec":"Contracts","secNum":5,"block":1,"q":"A liquidated damages clause specifies:","opts":["The bond amount","Pre-agreed damages for breach (often per day late)","The down payment","The warranty period"],"correct":1,"re":"Liquidated damages set a reasonable, agreed amount of damages for delay or breach."},
  {"id":65,"sec":"Contracts","secNum":5,"block":1,"q":"An express warranty is one that is:","opts":["Implied by law","Stated specifically by the contractor","Provided only by the manufacturer","Never enforceable"],"correct":1,"re":"An express warranty is a specific promise made in writing or words."},
  {"id":66,"sec":"Contracts","secNum":5,"block":1,"q":"The statute of limitations for a breach of a written contract in California is generally:","opts":["1 year","2 years","4 years","10 years"],"correct":2,"re":"Written-contract claims generally must be brought within 4 years."},
  {"id":67,"sec":"Contracts","secNum":5,"block":1,"q":"A home improvement contract must include a notice about:","opts":["The contractor's tax ID","The buyer's right to cancel and the CSLB","The bank's lien","The architect's seal"],"correct":1,"re":"HIC must contain required consumer notices, including cancellation rights and CSLB information."},
  {"id":68,"sec":"Contracts","secNum":5,"block":1,"q":"'Substantial performance' generally means the contractor:","opts":["Did nothing","Completed the essential purpose with only minor deviations","Breached the contract","Was unlicensed"],"correct":1,"re":"Substantial performance fulfills the contract's essential purpose with only trivial, correctable defects."},
  {"id":69,"sec":"Public Works","secNum":6,"block":1,"q":"On public works projects, workers must generally be paid:","opts":["Minimum wage","The prevailing wage","Whatever the contract states","Piece rate"],"correct":1,"re":"Public works require payment of the applicable prevailing wage."},
  {"id":70,"sec":"Public Works","secNum":6,"block":1,"q":"To bid or work on most public works, a contractor must be registered with the:","opts":["IRS","DIR (Department of Industrial Relations)","EPA","CSLB only"],"correct":1,"re":"Contractors must register with the DIR to bid on or perform public works."},
  {"id":71,"sec":"Public Works","secNum":6,"block":1,"q":"Certified payroll records on public works are submitted to verify:","opts":["Material costs","That prevailing wages were paid","Bond amounts","Permit fees"],"correct":1,"re":"Certified payroll documents that workers received the required prevailing wages."},
  {"id":72,"sec":"Public Works","secNum":6,"block":1,"q":"A bid bond on a public works project guarantees that the:","opts":["Subs are paid","Winning bidder will enter the contract","Work is defect-free","Wages are prevailing"],"correct":1,"re":"A bid bond assures the agency the low bidder will sign the contract and post required bonds."},
  {"id":73,"sec":"Public Works","secNum":6,"block":1,"q":"Prevailing wage rates are determined by the:","opts":["Contractor","Director of Industrial Relations","Local union only","CSLB"],"correct":1,"re":"The DIR Director sets prevailing wage determinations by craft and locality."},
  {"id":74,"sec":"Safety","secNum":7,"block":1,"q":"Every California employer must have a written:","opts":["Marketing plan","Injury and Illness Prevention Program (IIPP)","Bid schedule","Lien log"],"correct":1,"re":"Cal/OSHA requires every employer to maintain a written IIPP."},
  {"id":75,"sec":"Safety","secNum":7,"block":1,"q":"A serious injury, illness, or death at work must be reported to Cal/OSHA within:","opts":["8 hours","24 hours","48 hours","5 days"],"correct":0,"re":"Serious injuries/fatalities must be reported to Cal/OSHA within 8 hours."},
  {"id":76,"sec":"Safety","secNum":7,"block":1,"q":"'Lockout/tagout' procedures are used to:","opts":["Secure the job site at night","Control hazardous energy during service/maintenance","Lock the tool trailer","Tag finished work"],"correct":1,"re":"LOTO isolates and de-energizes equipment so it can't start during service."},
  {"id":77,"sec":"Safety","secNum":7,"block":1,"q":"An SDS (Safety Data Sheet) provides information about:","opts":["Wage rates","Hazardous chemicals and safe handling","Bond amounts","Building codes"],"correct":1,"re":"SDSs describe chemical hazards, handling, and first aid under the Hazard Communication standard."},
  {"id":78,"sec":"Safety","secNum":7,"block":1,"q":"Fall protection is generally required in construction at heights of:","opts":["4 feet","6 feet","10 feet","20 feet"],"correct":1,"re":"In construction, fall protection is generally required at 6 feet or more above a lower level."},
  {"id":79,"sec":"Safety","secNum":7,"block":1,"q":"A 'competent person' under Cal/OSHA is someone who can:","opts":["Sign contracts","Identify hazards and has authority to correct them","Issue licenses","Set prevailing wage"],"correct":1,"re":"A competent person recognizes hazards and is authorized to take prompt corrective action."},
  {"id":80,"sec":"Safety","secNum":7,"block":1,"q":"Before disturbing more than 100 sq ft of asbestos-containing material, a contractor must be:","opts":["Bonded for $50,000","Registered with Cal/OSHA for asbestos work","Licensed as a C-22 only","EPA 608 certified"],"correct":1,"re":"Asbestos work over 100 sq ft requires Cal/OSHA asbestos registration (and proper certification)."},
  {"id":81,"sec":"Safety","secNum":7,"block":1,"q":"PPE (personal protective equipment) is generally:","opts":["Bought by the employee","Provided by the employer when required","Optional always","Only for public works"],"correct":1,"re":"Employers must provide required PPE at no cost to employees."},
  {"id":82,"sec":"Safety","secNum":7,"block":1,"q":"A permit-required confined space is dangerous primarily because of:","opts":["Noise only","Atmospheric or engulfment hazards and limited exit","Cost","Cold temperatures"],"correct":1,"re":"Confined spaces pose atmospheric, engulfment, and entrapment hazards with restricted egress."},
  {"id":83,"sec":"Org & Licensing","secNum":1,"block":1,"q":"A contractor wanting to do plumbing, electrical, and HVAC as one firm would typically hold:","opts":["A single C-20","A B general building plus needed specialties, or each C-classification","An owner-builder permit","No license"],"correct":1,"re":"Multiple trades require the appropriate classifications (e.g., separate C-licenses) or a qualifying general (B) where allowed."},
  {"id":84,"sec":"Org & Licensing","secNum":1,"block":1,"q":"The CSLB's primary purpose is to:","opts":["Collect taxes","Protect the public by regulating the construction industry","Sell insurance","Set union wages"],"correct":1,"re":"The CSLB licenses and regulates contractors to protect consumers."},
  {"id":85,"sec":"Org & Licensing","secNum":1,"block":1,"q":"Advertising must include the contractor's:","opts":["Home address","License number","Bond company","Tax return"],"correct":1,"re":"Licensed contractors must show their license number in advertising."},
  {"id":86,"sec":"Business Finances","secNum":2,"block":1,"q":"Net income is:","opts":["Revenue before expenses","Revenue minus all expenses and taxes","Total assets","Owner contributions"],"correct":1,"re":"Net income is what remains after all expenses and taxes — the 'bottom line.'"},
  {"id":87,"sec":"Business Finances","secNum":2,"block":1,"q":"A balance sheet shows a company's financial position:","opts":["Over a year","At a single point in time","Only at tax time","For one job"],"correct":1,"re":"A balance sheet is a snapshot of assets, liabilities, and equity at a moment in time."},
  {"id":88,"sec":"Employment","secNum":3,"block":1,"q":"An apprentice on a public works job must be:","opts":["Unpaid","Registered in an approved apprenticeship program","Over 25","A union officer"],"correct":1,"re":"Apprentices must be enrolled in a state-approved apprenticeship program to be paid apprentice rates."},
  {"id":89,"sec":"Employment","secNum":3,"block":1,"q":"Failure to carry required workers' comp can result in:","opts":["A warning only","A stop order and license suspension","A tax credit","Nothing"],"correct":1,"re":"Operating without required workers' comp can trigger a stop order, penalties, and license suspension."},
  {"id":90,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"A subcontractor who did NOT have a direct contract with the owner usually must serve a preliminary notice to preserve:","opts":["Bonding rights","Lien and stop-payment-notice rights","Tax rights","License rights"],"correct":1,"re":"Without a direct contract with the owner, the preliminary notice preserves the claimant's lien and stop-payment rights."},
  {"id":91,"sec":"Insurance & Liens","secNum":4,"block":1,"q":"'Course of construction' (builder's risk) insurance covers:","opts":["Employee injuries","The project itself during construction","Auto accidents","Contract disputes"],"correct":1,"re":"Builder's risk insures the work/materials against loss during construction."},
  {"id":92,"sec":"Contracts","secNum":5,"block":1,"q":"If a contract term is ambiguous, courts often interpret it:","opts":["In favor of the contractor","Against the party who drafted it","As void","In favor of the bond"],"correct":1,"re":"Ambiguities are generally construed against the drafter."},
  {"id":93,"sec":"Contracts","secNum":5,"block":1,"q":"A unilateral mistake in a bid (e.g., math error) may allow the bidder to:","opts":["Never withdraw","Seek to withdraw/rescind if conditions are met","Double the price freely","Ignore the bid"],"correct":1,"re":"A genuine, material unilateral mistake promptly raised may permit rescission of the bid."},
  {"id":94,"sec":"Public Works","secNum":6,"block":1,"q":"On public works, the agency typically awards to the:","opts":["Lowest responsible, responsive bidder","Highest bidder","First bidder","Local bidder only"],"correct":0,"re":"Public contracts generally go to the lowest responsible and responsive bidder."},
  {"id":95,"sec":"Public Works","secNum":6,"block":1,"q":"Prevailing wage generally does NOT apply to:","opts":["Most public works over the threshold","Purely private residential remodels","State building projects","School district work"],"correct":1,"re":"Private projects are not public works, so prevailing wage generally doesn't apply."},
  {"id":96,"sec":"Safety","secNum":7,"block":1,"q":"Heat illness prevention rules in California require employers to provide:","opts":["Only water","Water, shade, rest, and training","Air conditioning on site","Bonuses"],"correct":1,"re":"Cal/OSHA heat standards require access to water, shade, rest breaks, and training."},
  {"id":97,"sec":"Safety","secNum":7,"block":1,"q":"Scaffolding over a certain height must be:","opts":["Built by anyone","Designed/inspected per Cal/OSHA and have guardrails","Removed daily","Bonded"],"correct":1,"re":"Scaffolds must meet Cal/OSHA design, guardrail, and inspection requirements."},
  {"id":98,"sec":"Org & Licensing","secNum":1,"block":1,"q":"An 'inactive' license means the contractor:","opts":["Can still bid","Cannot contract until reactivated, but keeps the number","Lost the license","Owes back taxes"],"correct":1,"re":"An inactive license preserves the number but doesn't authorize contracting until reactivated."},
  {"id":99,"sec":"Business Finances","secNum":2,"block":1,"q":"A break-even point is reached when:","opts":["Revenue exceeds assets","Total revenue equals total costs","Overhead is zero","Profit is maximized"],"correct":1,"re":"Break-even is where revenue exactly covers fixed plus variable costs — no profit, no loss."},
  {"id":100,"sec":"Contracts","secNum":5,"block":1,"q":"A contractor who abandons a job without legal excuse has likely committed:","opts":["Substantial performance","A material breach of contract","A change order","A lien waiver"],"correct":1,"re":"Unjustified abandonment is a material breach exposing the contractor to damages."},
  {"id":101,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"If the OWNER records a Notice of Completion, a SUBCONTRACTOR (not the direct contractor) must record a mechanics lien within:","opts":["10 days","30 days","60 days","90 days"],"correct":1,"re":"With an NOC recorded, subs/suppliers get 30 days; the direct contractor gets 60 days."},
  {"id":102,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"With a Notice of Completion recorded, the DIRECT (prime) contractor must record a mechanics lien within:","opts":["30 days","60 days","90 days","120 days"],"correct":1,"re":"NOC shortens the prime contractor's window to 60 days (vs. 90 with no NOC)."},
  {"id":103,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"A Notice of Cessation may be recorded by the owner after work has stopped continuously for at least:","opts":["7 days","15 days","30 days","60 days"],"correct":2,"re":"After 30 days of continuous cessation, the owner may record a Notice of Cessation, which (like an NOC) shortens lien windows."},
  {"id":104,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"The preliminary 20-day notice must be served on all of the following EXCEPT:","opts":["The owner","The direct contractor","The construction lender (if any)","The county tax collector"],"correct":3,"re":"The preliminary notice goes to the owner, the direct contractor, and the construction lender — not the tax collector."},
  {"id":105,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"A direct contractor who DID contract with the owner generally:","opts":["Must still serve a preliminary notice on the owner","Need not serve the owner a preliminary notice (but must notify any construction lender)","Loses lien rights entirely","Cannot record a lien"],"correct":1,"re":"A direct contractor need not preliminary-notice the owner they contracted with, but must notify any construction lender."},
  {"id":106,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"The amount of a mechanics lien is limited to:","opts":["The full contract price always","The reasonable value of work/materials furnished or the contract price, whichever is less","Double the unpaid balance","Any amount the claimant chooses"],"correct":1,"re":"A lien is limited to the lesser of the reasonable value furnished or the contract price, less amounts paid."},
  {"id":107,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"A 'Notice of Nonresponsibility' is used by:","opts":["A contractor avoiding wages","An owner who didn't authorize a tenant's work, to protect the property from liens","A lender","A subcontractor"],"correct":1,"re":"An owner records a Notice of Nonresponsibility to disclaim liability for improvements they didn't authorize (e.g., tenant work)."},
  {"id":108,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"A conditional lien waiver becomes effective:","opts":["Immediately on signing","Only after the payment actually clears","Never","After 90 days"],"correct":1,"re":"A conditional waiver is contingent on the payment actually being received/clearing."},
  {"id":109,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"California's statutory lien-waiver forms include all of the following EXCEPT:","opts":["Conditional waiver on progress payment","Unconditional waiver on progress payment","Conditional waiver on final payment","Permanent irrevocable lien"],"correct":3,"re":"There are four statutory forms (conditional/unconditional × progress/final); 'permanent irrevocable lien' is not one."},
  {"id":110,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"If a foreclosure suit is not filed within 90 days of recording the lien, the lien:","opts":["Doubles","Becomes unenforceable/expires","Converts to a bond","Transfers to the lender"],"correct":1,"re":"Failing to sue within 90 days renders the lien unenforceable and it should be released."},
  {"id":111,"sec":"Contracts","secNum":5,"block":2,"q":"The Subletting and Subcontracting Fair Practices Act ('Listing Law') requires a prime bidder on public works to:","opts":["Use only union subs","List each sub doing more than 0.5% of the bid (or $10,000 on street/highway)","Self-perform everything","Pay subs in advance"],"correct":1,"re":"Primes must list subs performing more than one-half of 1% of the total bid, to curb bid shopping."},
  {"id":112,"sec":"Contracts","secNum":5,"block":2,"q":"'Bid shopping' refers to a prime contractor who, after award:","opts":["Compares insurance quotes","Pressures listed subs to lower prices or swaps them out improperly","Files a lien","Pays prevailing wage"],"correct":1,"re":"Bid shopping is using a low bid to squeeze or replace subcontractors after the contract is awarded — restricted by the Listing Law."},
  {"id":113,"sec":"Contracts","secNum":5,"block":2,"q":"Once a sub is listed, the prime may substitute that sub only:","opts":["At will","For statutory cause with the awarding authority's consent","If the price changes","Never"],"correct":1,"re":"Substitution of a listed sub requires a recognized statutory reason and the public agency's consent."},
  {"id":114,"sec":"Contracts","secNum":5,"block":2,"q":"A sub's bid that the prime reasonably relied on may be held to the prime under:","opts":["Quantum meruit","Promissory estoppel","Novation","Subrogation"],"correct":1,"re":"Promissory estoppel can bind a sub to a bid the prime reasonably relied on in its own bid."},
  {"id":115,"sec":"Contracts","secNum":5,"block":2,"q":"A 'novation' is:","opts":["A minor change order","Substituting a new contract/party for an old one, with all parties' consent","A bond claim","A lien"],"correct":1,"re":"Novation replaces an original contract or party with a new one by mutual agreement, extinguishing the old obligation."},
  {"id":116,"sec":"Contracts","secNum":5,"block":2,"q":"'Quantum meruit' allows recovery of:","opts":["Punitive damages","The reasonable value of services where no enforceable price was set","Triple damages","Lien interest"],"correct":1,"re":"Quantum meruit awards the reasonable value of work performed when no enforceable contract price exists."},
  {"id":117,"sec":"Contracts","secNum":5,"block":2,"q":"A home improvement contract must contain a schedule of payments that is:","opts":["100% up front","Tied to the value of work performed and materials delivered","Paid only at the end","Set by the lender"],"correct":1,"re":"HIC payments must reasonably correspond to work performed and materials delivered — not front-loaded."},
  {"id":118,"sec":"Contracts","secNum":5,"block":2,"q":"For service and repair contracts (specific exemption), the cash down payment limit is generally:","opts":["No special limit beyond the $1,000/10% HIC rule unless service-and-repair conditions are met","Always 50%","Always $5,000","Zero"],"correct":0,"re":"Standard HIC down-payment caps apply unless the strict statutory 'service and repair' conditions are met."},
  {"id":119,"sec":"Contracts","secNum":5,"block":2,"q":"A 'Mechanics Lien Warning' notice must be given to the owner:","opts":["After completion","As part of the home improvement contract documents","Only on public works","Never"],"correct":1,"re":"HIC paperwork must include the required notice informing owners about mechanics lien rights of subs/suppliers."},
  {"id":120,"sec":"Org & Licensing","secNum":1,"block":2,"q":"Under B&P Code §7000s, the registrar may issue a citation that includes:","opts":["Jail time","An order of correction and a civil penalty","License revocation only","Criminal fines only"],"correct":1,"re":"A CSLB citation may order correction and assess a civil penalty without a full disciplinary hearing."},
  {"id":121,"sec":"Org & Licensing","secNum":1,"block":2,"q":"'Abandonment' of a construction project without legal excuse is, under the license law:","opts":["Allowed if paid","Grounds for disciplinary action against the license","A felony always","Only a contract issue"],"correct":1,"re":"Willful abandonment is a statutory ground for CSLB discipline."},
  {"id":122,"sec":"Org & Licensing","secNum":1,"block":2,"q":"Departure from accepted trade standards ('departure from plans/specs') is disciplinable when it is:","opts":["Any deviation","Willful or fraudulent and causes harm","Approved by the owner","A minor cosmetic change"],"correct":1,"re":"Willful departure from plans/specs or trade standards, causing injury, is grounds for discipline."},
  {"id":123,"sec":"Org & Licensing","secNum":1,"block":2,"q":"Aiding an unlicensed person to evade the license law is:","opts":["Permitted for friends","A violation that can lead to discipline","Allowed under $5,000","Encouraged by CSLB"],"correct":1,"re":"Helping an unlicensed person contract is itself a violation of the license law."},
  {"id":124,"sec":"Org & Licensing","secNum":1,"block":2,"q":"The CSLB may suspend a license automatically for an unsatisfied:","opts":["Parking ticket","Construction-related court judgment not paid within 90 days","Marketing complaint","Late tax filing"],"correct":1,"re":"An unpaid construction-related judgment can trigger automatic suspension if not resolved within 90 days."},
  {"id":125,"sec":"Org & Licensing","secNum":1,"block":2,"q":"A 'disciplinary bond' may be required by the registrar when a contractor:","opts":["Renews on time","Has a history of violations/has been disciplined","Is newly licensed only","Carries GL insurance"],"correct":1,"re":"A disciplinary bond can be imposed on licensees with a record of violations as a condition of licensure."},
  {"id":126,"sec":"Org & Licensing","secNum":1,"block":2,"q":"The statute of limitations for the CSLB to bring most disciplinary actions is generally within:","opts":["1 year of the act","4 years of the act (or 2 years for some), with discovery rules","10 years","No limit ever"],"correct":1,"re":"CSLB discipline generally must begin within set periods (often within four years of the act, subject to discovery rules)."},
  {"id":127,"sec":"Business Finances","secNum":2,"block":2,"q":"A contractor's overhead is $90,000/year and target net profit is $30,000. To cover both on $600,000 of direct job costs, the needed markup is about:","opts":["10%","20%","25%","33%"],"correct":1,"re":"($90k + $30k) ÷ $600k = 20% markup on costs."},
  {"id":128,"sec":"Business Finances","secNum":2,"block":2,"q":"If a job sells for $10,000 with a 25% margin (on price), the cost was:","opts":["$7,000","$7,500","$8,000","$8,500"],"correct":1,"re":"Margin on price: cost = $10,000 × (1 − 0.25) = $7,500."},
  {"id":129,"sec":"Business Finances","secNum":2,"block":2,"q":"Markup and margin differ because markup is figured on ____ and margin on ____:","opts":["price; cost","cost; selling price","profit; revenue","tax; income"],"correct":1,"re":"Markup is a percentage of cost; margin is a percentage of selling price."},
  {"id":130,"sec":"Business Finances","secNum":2,"block":2,"q":"'Retention' (retainage) on a contract is:","opts":["Tax withheld","A percentage of progress payments held back until completion","A bond","Overtime"],"correct":1,"re":"Retention is a portion of each payment withheld to ensure completion, released at the end."},
  {"id":131,"sec":"Business Finances","secNum":2,"block":2,"q":"A contractor using the 'completed-contract' method recognizes profit:","opts":["As cash arrives","When the contract is substantially complete","Monthly","At signing"],"correct":1,"re":"Completed-contract defers profit recognition until the job is essentially done."},
  {"id":132,"sec":"Business Finances","secNum":2,"block":2,"q":"The 'percentage-of-completion' method recognizes revenue:","opts":["Only at the end","In proportion to work completed over the contract","Never","At bid time"],"correct":1,"re":"Percentage-of-completion books revenue as the project progresses."},
  {"id":133,"sec":"Business Finances","secNum":2,"block":2,"q":"Estimated quarterly tax payments to the IRS are generally required for:","opts":["W-2 employees","Self-employed/owners expecting to owe $1,000+ in tax","Apprentices","Bondholders"],"correct":1,"re":"Self-employed individuals generally pay estimated taxes quarterly when they expect to owe $1,000 or more."},
  {"id":134,"sec":"Employment","secNum":3,"block":2,"q":"On the 7th consecutive day of work in a workweek, the first 8 hours are paid at:","opts":["Straight time","1.5×","2×","No pay"],"correct":1,"re":"The first 8 hours on the 7th consecutive day are at 1.5×; over 8 that day is 2×."},
  {"id":135,"sec":"Employment","secNum":3,"block":2,"q":"An employer must register with the EDD after paying wages over ____ in a calendar quarter:","opts":["$100","$500","$1,000","$5,000"],"correct":0,"re":"Once an employer pays over $100 in wages in a quarter, it must register with the EDD."},
  {"id":136,"sec":"Employment","secNum":3,"block":2,"q":"Form DE 9 / DE 9C filed with the EDD reports:","opts":["Federal income tax only","Quarterly wages and state payroll taxes","Sales tax","Mechanics liens"],"correct":1,"re":"The DE 9 and DE 9C report quarterly wages and California payroll tax contributions."},
  {"id":137,"sec":"Employment","secNum":3,"block":2,"q":"A 'waiting time penalty' for late final wages can be up to:","opts":["1 day's pay","8 hours' pay","30 days' wages","One year's wages"],"correct":2,"re":"Willfully late final wages can cost up to 30 days of the employee's daily wage."},
  {"id":138,"sec":"Employment","secNum":3,"block":2,"q":"Under the ABC test, prong 'B' requires the worker to perform work that is:","opts":["Inside the hirer's usual business","Outside the hiring entity's usual course of business","On public works","For union members"],"correct":1,"re":"Prong B requires the work be outside the hirer's usual business to be an independent contractor."},
  {"id":139,"sec":"Employment","secNum":3,"block":2,"q":"Overtime exemptions (e.g., 'executive') generally require the employee to:","opts":["Just have a title","Meet salary AND duties tests","Work part-time","Be on public works"],"correct":1,"re":"Exempt status requires meeting both a minimum salary threshold and specific duties tests."},
  {"id":140,"sec":"Employment","secNum":3,"block":2,"q":"An employer who pays cash 'under the table' to avoid payroll taxes risks:","opts":["Nothing","Tax fraud charges, penalties, and license discipline","A refund","A bonus"],"correct":1,"re":"Off-the-books cash payroll exposes the employer to tax fraud, penalties, and CSLB discipline."},
  {"id":141,"sec":"Employment","secNum":3,"block":2,"q":"Paid sick leave in California generally accrues at a minimum of:","opts":["1 hour per 10 hours worked","1 hour per 30 hours worked","1 day per month","Only for full-time"],"correct":1,"re":"Statewide paid sick leave accrues at least 1 hour for every 30 hours worked (verify current local minimums)."},
  {"id":142,"sec":"Employment","secNum":3,"block":2,"q":"Form W-2 must be furnished to employees by:","opts":["April 15","January 31","June 30","December 31"],"correct":1,"re":"Employers must provide W-2s to employees by January 31."},
  {"id":143,"sec":"Public Works","secNum":6,"block":2,"q":"On public works, the threshold above which contractor DIR registration is generally required for new projects is about:","opts":["$0","$15,000 (and $25,000 for awards), subject to current law","$100,000","$1 million"],"correct":1,"re":"Small-project exemptions exist (roughly $15,000 work / $25,000 award thresholds) — verify current figures."},
  {"id":144,"sec":"Public Works","secNum":6,"block":2,"q":"Certified payroll on public works must generally be submitted:","opts":["Once at the end","Weekly (or per agency schedule) via the DIR eCPR system","Annually","Never"],"correct":1,"re":"Contractors submit certified payroll records (often weekly) electronically through DIR."},
  {"id":145,"sec":"Public Works","secNum":6,"block":2,"q":"Prevailing wage includes the basic hourly rate PLUS:","opts":["Only overtime","Fringe benefits (health, pension, training)","Sales tax","Bond premiums"],"correct":1,"re":"Prevailing wage is the basic rate plus required fringe benefit contributions."},
  {"id":146,"sec":"Public Works","secNum":6,"block":2,"q":"Failure to pay prevailing wages can result in:","opts":["A thank-you letter","Penalties, back wages, and debarment from public works","A tax credit","A larger bond return"],"correct":1,"re":"Underpaying prevailing wages can bring penalties, restitution, and debarment from bidding public works."},
  {"id":147,"sec":"Public Works","secNum":6,"block":2,"q":"A Stop Payment Notice on a PUBLIC works project is served on the:","opts":["County recorder","Public entity holding the funds","Bonding company","Subcontractor"],"correct":1,"re":"On public works there are no liens against the property; a stop payment notice reaches funds held by the public entity."},
  {"id":148,"sec":"Public Works","secNum":6,"block":2,"q":"On public works, instead of a mechanics lien, an unpaid sub typically pursues the:","opts":["Property title","Payment bond and/or stop payment notice","Owner's home","CSLB bond only"],"correct":1,"re":"Public property can't be liened; remedies are the statutory payment bond and stop payment notice."},
  {"id":149,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"A 'Little Miller Act' payment bond on California public works protects:","opts":["The agency only","Subcontractors and suppliers who go unpaid","The bonding company","Taxpayers from cost overruns"],"correct":1,"re":"The payment bond required on public works secures payment to subs and suppliers."},
  {"id":150,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"A claim against a contractor's CSLB bond is generally limited to harm caused by:","opts":["Any contract dispute","Specified violations of the license law (e.g., to consumers/employees)","Marketing","Tax issues"],"correct":1,"re":"The contractor's bond covers specific statutory violations harming homeowners, employees, and certain others."},
  {"id":151,"sec":"Contracts","secNum":5,"block":2,"q":"A 'time is of the essence' clause means:","opts":["Deadlines are flexible","Timely performance is a material term; lateness is a breach","Only the price matters","The bond controls timing"],"correct":1,"re":"This clause makes the completion dates material, so delay is a breach."},
  {"id":152,"sec":"Contracts","secNum":5,"block":2,"q":"A contract provision requiring disputes to go to a neutral third party's binding decision is:","opts":["Mediation","Arbitration","Litigation","Estoppel"],"correct":1,"re":"Arbitration submits the dispute to a neutral whose decision is typically binding."},
  {"id":153,"sec":"Contracts","secNum":5,"block":2,"q":"Mediation differs from arbitration because mediation is:","opts":["Binding","Non-binding; the mediator helps parties reach their own agreement","Decided by a judge","Only for public works"],"correct":1,"re":"A mediator facilitates a voluntary settlement and does not impose a decision."},
  {"id":154,"sec":"Contracts","secNum":5,"block":2,"q":"The 'parol evidence rule' limits use of:","opts":["Bond claims","Prior oral statements to contradict a complete written contract","Lien notices","Change orders"],"correct":1,"re":"Parol evidence generally bars prior/contemporaneous oral terms that contradict a fully integrated written contract."},
  {"id":155,"sec":"Contracts","secNum":5,"block":2,"q":"An 'implied warranty of merchantability' means goods/materials are:","opts":["Free","Fit for their ordinary purpose","Always custom","Tax-exempt"],"correct":1,"re":"Merchantable goods are reasonably fit for the ordinary purposes for which they're used."},
  {"id":156,"sec":"Contracts","secNum":5,"block":2,"q":"A contractor's standard workmanship warranty in California is often expressed as:","opts":["No warranty","One year, separate from statutory defect limitations","Lifetime always","Only what the bond covers"],"correct":1,"re":"Contractors commonly warrant workmanship (e.g., 1 year), in addition to statutory limitation periods for defects."},
  {"id":157,"sec":"Contracts","secNum":5,"block":2,"q":"For latent (hidden) construction defects, California's statute of repose is generally:","opts":["1 year","4 years","10 years","No limit"],"correct":2,"re":"Latent defect claims generally must be brought within 10 years of substantial completion."},
  {"id":158,"sec":"Contracts","secNum":5,"block":2,"q":"For patent (obvious) construction defects, the limitations period is generally:","opts":["1 year","4 years","10 years","20 years"],"correct":1,"re":"Patent defects generally have a 4-year limitations period."},
  {"id":159,"sec":"Contracts","secNum":5,"block":2,"q":"The 'Right to Repair Act' (SB 800) primarily governs:","opts":["Public works wages","Residential new-construction defect claims and a pre-litigation process","Commercial leases","Auto repair"],"correct":1,"re":"SB 800 sets standards and a notice-and-repair process for defects in new residential construction."},
  {"id":160,"sec":"Contracts","secNum":5,"block":2,"q":"A liquidated damages clause is unenforceable if the stated amount is:","opts":["A reasonable estimate","An unreasonable penalty far exceeding likely harm","Per day","Agreed in writing"],"correct":1,"re":"Liquidated damages must be a reasonable forecast of harm; a punitive amount is unenforceable."},
  {"id":161,"sec":"Org & Licensing","secNum":1,"block":2,"q":"A contractor who allows another person to use their license number to pull permits is engaged in:","opts":["A legal arrangement","Unlawful 'license renting,' a serious violation","Joint venture licensing","An RME setup"],"correct":1,"re":"Lending or 'renting' a license number is a serious violation of the license law."},
  {"id":162,"sec":"Org & Licensing","secNum":1,"block":2,"q":"To add a classification to an existing license, the qualifier generally must:","opts":["Pay a fee only","Pass the trade exam for that classification (unless waived)","Wait 5 years","Form a new corporation"],"correct":1,"re":"A new classification typically requires passing the relevant trade exam (with limited waivers)."},
  {"id":163,"sec":"Org & Licensing","secNum":1,"block":2,"q":"An owner-builder exemption generally does NOT apply when the owner:","opts":["Builds for personal use and doesn't sell quickly","Builds intending to sell, exceeding the statutory limits","Hires licensed subs","Lives in the home"],"correct":1,"re":"The owner-builder exemption is limited; building structures for sale beyond statutory limits requires a license."},
  {"id":164,"sec":"Employment","secNum":3,"block":2,"q":"A contractor must keep payroll records for at least (commonly):","opts":["30 days","6 months","3–4 years (verify by record type)","No requirement"],"correct":2,"re":"Payroll and tax records are generally retained for several years (often 3–4); verify by record type and agency."},
  {"id":165,"sec":"Employment","secNum":3,"block":2,"q":"An employer's responsibility for an employee's negligent acts within the scope of employment is:","opts":["Estoppel","Respondeat superior (vicarious liability)","Novation","Subrogation"],"correct":1,"re":"Under respondeat superior, employers are vicariously liable for employees' on-the-job negligence."},
  {"id":166,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"'Subrogation' in insurance means the insurer:","opts":["Cancels the policy","Steps into the insured's rights to recover from the at-fault party","Doubles the premium","Issues a bond"],"correct":1,"re":"After paying a claim, the insurer is subrogated to the insured's recovery rights against the responsible party."},
  {"id":167,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"An 'additional insured' endorsement typically:","opts":["Insures the contractor's truck","Extends a policy's coverage to another party (e.g., the owner/GC)","Replaces workers' comp","Pays liens"],"correct":1,"re":"It extends the named policy's protection to another party, common in subcontract requirements."},
  {"id":168,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"A 'certificate of insurance' is:","opts":["The full policy","Proof of coverage summary, not the policy itself","A bond","A lien waiver"],"correct":1,"re":"A COI summarizes coverage but does not by itself confer or replace the policy terms."},
  {"id":169,"sec":"Business Finances","secNum":2,"block":2,"q":"A 'profit & overhead' (P&O / 'O&P') markup on insurance-restoration work is commonly cited as:","opts":["5%","10% and 10% (≈20%)","50%","100%"],"correct":1,"re":"The traditional general-contractor O&P on restoration is often cited as 10% overhead + 10% profit."},
  {"id":170,"sec":"Business Finances","secNum":2,"block":2,"q":"A contractor's 'cost of goods sold' on a job would include:","opts":["Office rent","Direct labor, materials, and subcontracts for that job","The owner's salary","Marketing"],"correct":1,"re":"COGS captures the direct job costs: labor, materials, equipment, and subs for that project."},
  {"id":171,"sec":"Contracts","secNum":5,"block":2,"q":"A 'pay-when-paid' clause is generally interpreted in California as:","opts":["A condition that erases the sub's right to payment","A reasonable-time provision; the sub must still eventually be paid","Always void","Identical to pay-if-paid and enforceable"],"correct":1,"re":"California disfavors true 'pay-if-paid' conditions; 'pay-when-paid' is read as allowing a reasonable time to pay."},
  {"id":172,"sec":"Contracts","secNum":5,"block":2,"q":"A contractor may NOT enforce a contract clause that requires the buyer to waive:","opts":["The down payment","Statutory consumer protections / lien rights in advance, where prohibited","The completion date","The warranty"],"correct":1,"re":"Advance waivers of certain statutory protections (e.g., lien rights) are unenforceable where the law forbids them."},
  {"id":173,"sec":"Public Works","secNum":6,"block":2,"q":"A 'project labor agreement' (PLA) on public works is:","opts":["A bond","A pre-hire collective bargaining agreement setting terms for the project","A lien","A permit"],"correct":1,"re":"A PLA is a pre-hire agreement establishing labor terms for a specific public project."},
  {"id":174,"sec":"Public Works","secNum":6,"block":2,"q":"Apprenticeship 'ratio' requirements on public works mean:","opts":["No apprentices allowed","A set ratio of apprentice-to-journeyman hours must be met","Only journeymen work","Apprentices are unpaid"],"correct":1,"re":"Public works often require employing apprentices at a defined ratio to journeyman hours."},
  {"id":175,"sec":"Safety","secNum":7,"block":2,"q":"A Cal/OSHA 'serious violation' citation means:","opts":["A paperwork error","A substantial probability of death or serious physical harm","A minor housekeeping issue","An advertising mistake"],"correct":1,"re":"A serious violation involves a realistic probability of death or serious physical harm."},
  {"id":176,"sec":"Safety","secNum":7,"block":2,"q":"A 'willful' Cal/OSHA violation carries higher penalties because the employer:","opts":["Made an honest mistake","Knew of the requirement and intentionally disregarded it","Was a small business","Had no employees"],"correct":1,"re":"Willful violations involve intentional disregard or plain indifference to a known requirement."},
  {"id":177,"sec":"Safety","secNum":7,"block":2,"q":"Cal/OSHA Form 300 is used to:","opts":["File taxes","Log recordable work-related injuries and illnesses","Apply for a license","Record liens"],"correct":1,"re":"The Form 300 log records work-related injuries and illnesses; the 300A is the annual summary."},
  {"id":178,"sec":"Safety","secNum":7,"block":2,"q":"Excavations 5 feet or deeper generally require:","opts":["No precautions","A protective system (sloping, shoring, or shielding) unless stable rock","A bond","A permit only"],"correct":1,"re":"Trenches/excavations 5 ft+ need cave-in protection unless made entirely in stable rock."},
  {"id":179,"sec":"Safety","secNum":7,"block":2,"q":"A Cal/OSHA excavation permit is generally required for trenches deeper than:","opts":["3 feet","5 feet","10 feet (for permit; protection still needed at 5 ft)","20 feet"],"correct":2,"re":"A Cal/OSHA permit is generally required for trenches/excavations 5 ft deep where workers enter; an annual permit covers most; project permits apply to deeper work (verify current rule)."},
  {"id":180,"sec":"Safety","secNum":7,"block":2,"q":"Before digging, a contractor must contact the regional notification center (call/click 811) to:","opts":["Order materials","Have underground utilities marked (DigAlert)","Get a license","File a lien"],"correct":1,"re":"Calling 811/DigAlert before excavation has utilities located and marked to prevent strikes."},
  {"id":181,"sec":"Org & Licensing","secNum":1,"block":2,"q":"If a corporation's only qualifying RMO leaves, the license is:","opts":["Unaffected","Subject to suspension if not replaced within the allowed period","Automatically revoked same day","Converted to a sole prop"],"correct":1,"re":"Losing the qualifier can lead to suspension if a replacement isn't reported within the statutory window (e.g., 90 days)."},
  {"id":182,"sec":"Org & Licensing","secNum":1,"block":2,"q":"A contractor must report a conviction or specified adverse license action to CSLB because:","opts":["It's optional","Failure to disclose is itself a violation","CSLB never asks","Only felonies matter for ads"],"correct":1,"re":"Licensees have a duty to report certain convictions/actions; concealment is a violation."},
  {"id":183,"sec":"Business Finances","secNum":2,"block":2,"q":"A 'fixed-price' (lump-sum) contract places the risk of cost overruns mainly on the:","opts":["Owner","Contractor","Lender","Bond company"],"correct":1,"re":"In a lump-sum contract, the contractor bears overrun risk for the agreed scope."},
  {"id":184,"sec":"Business Finances","secNum":2,"block":2,"q":"A 'cost-plus' contract reimburses costs plus a fee, shifting overrun risk toward the:","opts":["Contractor","Owner","Subcontractor","Insurer"],"correct":1,"re":"Cost-plus shifts more cost-overrun risk to the owner, who pays actual costs plus the fee."},
  {"id":185,"sec":"Contracts","secNum":5,"block":2,"q":"A 'scope of work' that is vague most often leads to:","opts":["Lower price","Disputes and change-order conflicts","Faster completion","Bond claims by owner"],"correct":1,"re":"Vague scope breeds disagreement over what's included, driving disputes and change orders."},
  {"id":186,"sec":"Contracts","secNum":5,"block":2,"q":"In a home improvement contract, the total contract price must be:","opts":["Estimated only","Stated as a specific dollar amount (or a clear method to compute it)","Hidden until completion","Set by the lender"],"correct":1,"re":"HICs must state the total price clearly so the consumer knows the full cost."},
  {"id":187,"sec":"Employment","secNum":3,"block":2,"q":"Independent-contractor status is LEAST supported when the worker:","opts":["Has their own license and tools","Sets their own hours","Works only for one hirer, doing the hirer's core work, under direction","Invoices for projects"],"correct":2,"re":"Working solely for one hirer, on its core business, under its control points to employee status."},
  {"id":188,"sec":"Employment","secNum":3,"block":2,"q":"A C-20 contractor hiring helpers and paying them hourly under his direction has created:","opts":["Independent contractors","An employer-employee relationship requiring payroll compliance","A partnership","A joint venture"],"correct":1,"re":"Hourly helpers under the contractor's control are employees, triggering payroll tax and workers' comp duties."},
  {"id":189,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"A contractor's failure to maintain the required bond results in:","opts":["A warning only","License suspension until the bond is restored","A tax penalty","Nothing"],"correct":1,"re":"The license is suspended if the required bond lapses, until coverage is reinstated."},
  {"id":190,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"A 'completion bond' differs from a performance bond in that it primarily assures:","opts":["Sub payment","The lender/owner the project will be finished free of liens","Prevailing wage","The bid price"],"correct":1,"re":"A completion bond assures financing parties the project will be completed and lien-free."},
  {"id":191,"sec":"Public Works","secNum":6,"block":2,"q":"On public works, falsifying certified payroll is:","opts":["A clerical issue","A serious offense that can lead to penalties, debarment, and criminal exposure","Encouraged","Allowed under $25,000"],"correct":1,"re":"Falsifying certified payroll can bring civil penalties, debarment, and criminal liability."},
  {"id":192,"sec":"Public Works","secNum":6,"block":2,"q":"A public agency may withhold contract payments to enforce:","opts":["Marketing rules","Prevailing wage and labor compliance","Bond renewals","License ads"],"correct":1,"re":"Agencies can withhold payments to secure prevailing-wage and labor-law compliance."},
  {"id":193,"sec":"Safety","secNum":7,"block":2,"q":"Respirator use on a job that has respiratory hazards requires:","opts":["Any mask","A written respiratory protection program with fit testing and medical evaluation","Nothing for short tasks","Only eye protection"],"correct":1,"re":"Required respirator use triggers a written program, medical clearance, and fit testing."},
  {"id":194,"sec":"Safety","secNum":7,"block":2,"q":"The Hazard Communication standard's 'right to know' covers employees' access to:","opts":["Payroll","Chemical hazard info, labels, and SDSs","Bond details","Bid results"],"correct":1,"re":"HazCom guarantees workers information about chemical hazards via labels, SDSs, and training."},
  {"id":195,"sec":"Safety","secNum":7,"block":2,"q":"GFCI protection on construction sites is required to prevent:","opts":["Overtime","Electric shock from ground faults","Theft","Noise"],"correct":1,"re":"Ground-fault circuit interrupters protect workers from shock due to ground faults."},
  {"id":196,"sec":"Org & Licensing","secNum":1,"block":2,"q":"The 'Contractors State License Law' is found primarily in the California:","opts":["Penal Code","Business and Professions Code (§7000 et seq.)","Vehicle Code","Tax Code"],"correct":1,"re":"The license law is in B&P Code beginning at §7000."},
  {"id":197,"sec":"Business Finances","secNum":2,"block":2,"q":"A contractor who consistently underbids and runs out of cash mid-project most likely failed at:","opts":["Marketing","Estimating and cash-flow planning","Safety","Lien filing"],"correct":1,"re":"Chronic underbidding and cash shortfalls point to weak estimating and cash-flow management."},
  {"id":198,"sec":"Contracts","secNum":5,"block":2,"q":"An 'integration clause' in a contract states that the written document:","opts":["Can be changed orally anytime","Is the complete and final agreement of the parties","Is only an estimate","Needs no signatures"],"correct":1,"re":"An integration (merger) clause confirms the writing is the parties' complete final agreement."},
  {"id":199,"sec":"Insurance & Liens","secNum":4,"block":2,"q":"A contractor who pulls a permit but lets an unlicensed person do the actual contracting may face:","opts":["No issue","Discipline for aiding unlicensed activity and license-law violations","A tax refund","A bond increase only"],"correct":1,"re":"Fronting permits for unlicensed work violates the license law and invites discipline."},
  {"id":200,"sec":"Contracts","secNum":5,"block":2,"q":"The single best protection against payment disputes on a home improvement job is a:","opts":["Verbal promise","Clear written contract with defined scope, price, and payment schedule","Larger down payment","Bigger bond"],"correct":1,"re":"A clear, complete written contract aligned to work performed is the strongest defense against payment disputes."},
  {"id":201,"sec":"Employment","secNum":3,"block":3,"q":"An employee who quits WITH at least 72 hours' notice must receive final wages:","opts":["Within 72 hours after","On the next regular payday","On their last day of work","Within 30 days"],"correct":2,"re":"With 72+ hours' notice, final wages are due on the employee's last day."},
  {"id":202,"sec":"Employment","secNum":3,"block":3,"q":"Reporting-time pay: an employee who reports as scheduled but is sent home early must be paid for at least:","opts":["1 hour","Half the scheduled shift (min 2, max 4 hours)","The full shift","Nothing"],"correct":1,"re":"Reporting-time pay is half the scheduled shift, with a minimum of 2 and maximum of 4 hours at the regular rate."},
  {"id":203,"sec":"Employment","secNum":3,"block":3,"q":"A 'split shift' premium in California is generally:","opts":["Double time","One extra hour at the minimum wage","No premium","Time and a half"],"correct":1,"re":"When a schedule is split by unpaid non-meal time, the employer owes one extra hour at minimum wage (offset rules apply)."},
  {"id":204,"sec":"Employment","secNum":3,"block":3,"q":"If an employer fails to provide a required meal or rest break, the penalty is:","opts":["A written warning","One additional hour of pay at the regular rate","Termination","Nothing"],"correct":1,"re":"A missed meal or rest period owes one premium hour at the regular rate (one per category per day)."},
  {"id":205,"sec":"Employment","secNum":3,"block":3,"q":"The California new-hire reporting form filed with the EDD is the:","opts":["DE 9","DE 34","DE 542","W-2"],"correct":1,"re":"Form DE 34 reports newly hired employees to the EDD within 20 days."},
  {"id":206,"sec":"Employment","secNum":3,"block":3,"q":"Independent contractors paid $600+ are reported to the EDD on:","opts":["DE 34","DE 542","Form I-9","Form 940"],"correct":1,"re":"Form DE 542 reports independent contractor service payments of $600 or more to the EDD."},
  {"id":207,"sec":"Employment","secNum":3,"block":3,"q":"Federal unemployment tax (FUTA) is reported annually on IRS:","opts":["Form 941","Form 940","Form W-4","Form 1099"],"correct":1,"re":"Form 940 reports annual FUTA; Form 941 reports quarterly withholding and FICA."},
  {"id":208,"sec":"Employment","secNum":3,"block":3,"q":"A worker's compensation premium is based primarily on:","opts":["Number of trucks","Payroll, classification codes, and the experience modifier","Square footage","Bond amount"],"correct":1,"re":"WC premium = payroll × class-code rate × experience modifier (X-Mod)."},
  {"id":209,"sec":"Employment","secNum":3,"block":3,"q":"An 'experience modifier' (X-Mod) above 1.0 means the employer's claims history is:","opts":["Better than average (lowers premium)","Worse than average (raises premium)","Irrelevant","Tax-deductible"],"correct":1,"re":"An X-Mod over 1.0 reflects worse-than-average losses and raises the WC premium."},
  {"id":210,"sec":"Employment","secNum":3,"block":3,"q":"An itemized wage statement (pay stub) under Labor Code §226 must include:","opts":["Only net pay","Gross wages, hours, rates, deductions, dates, and employer info","Only the employee's name","The bond number"],"correct":1,"re":"§226 requires nine specific items, including gross/net wages, hours, rates, deductions, pay period, and employer identity."},
  {"id":211,"sec":"Employment","secNum":3,"block":3,"q":"A licensed subcontractor performing work under their own license is generally:","opts":["Your employee","Not your employee for payroll/WC purposes","Always an apprentice","Exempt from prevailing wage"],"correct":1,"re":"A genuine licensed sub running their own business is not the prime's employee for payroll and workers' comp."},
  {"id":212,"sec":"Employment","secNum":3,"block":3,"q":"For overtime, an employee's 'regular rate of pay' must include:","opts":["Only base hourly wage","Nondiscretionary bonuses and certain incentives","Tips only","Mileage reimbursement"],"correct":1,"re":"The regular rate used for OT includes nondiscretionary bonuses and incentive pay, not just base wage."},
  {"id":213,"sec":"Employment","secNum":3,"block":3,"q":"The California statewide minimum wage effective January 1, 2026 is:","opts":["$15.50/hr","$16.50/hr","$16.90/hr","$20.00/hr"],"correct":2,"re":"The statewide minimum wage is $16.90/hr in 2026 (local and industry rates may be higher)."},
  {"id":214,"sec":"Employment","secNum":3,"block":3,"q":"The 2026 minimum salary for a full-time exempt employee in California is:","opts":["$54,080","$66,560","$70,304","$100,000"],"correct":2,"re":"Exempt employees must earn at least 2× minimum wage full-time = $70,304/yr in 2026."},
  {"id":215,"sec":"Employment","secNum":3,"block":3,"q":"I-9 forms must be retained for:","opts":["1 year from hire","3 years from hire or 1 year after termination, whichever is later","Forever","Until the next audit"],"correct":1,"re":"Keep I-9s for 3 years after hire or 1 year after termination, whichever is later."},
  {"id":216,"sec":"Employment","secNum":3,"block":3,"q":"California Paid Family Leave (PFL) benefits are funded through:","opts":["The employer directly","SDI deductions from employee wages","Federal grants","Workers' comp"],"correct":1,"re":"PFL is part of the SDI program, funded by employee wage deductions."},
  {"id":217,"sec":"Employment","secNum":3,"block":3,"q":"Required state and federal labor-law posters must be:","opts":["Emailed yearly","Displayed where employees can readily see them","Filed with CSLB","Optional for small firms"],"correct":1,"re":"Employers must post current labor-law notices in a conspicuous workplace location."},
  {"id":218,"sec":"Employment","secNum":3,"block":3,"q":"Mandatory paid sick leave generally lets employers cap annual use at:","opts":["8 hours","24 hours / 3 days (or 40/5 under newer rules — verify)","No cap","80 hours"],"correct":1,"re":"Employers may cap usage (historically 24 hours/3 days; newer law raised minimums — verify current)."},
  {"id":219,"sec":"Employment","secNum":3,"block":3,"q":"Hiring a worker, controlling their hours, and providing tools most likely makes them a(n):","opts":["Independent contractor","Employee","Vendor","Partner"],"correct":1,"re":"Control over hours, tools, and method points to employee status under the ABC test."},
  {"id":220,"sec":"Employment","secNum":3,"block":3,"q":"Willful failure to pay all wages owed at separation can trigger:","opts":["A bonus","Waiting-time penalties up to 30 days' wages","A tax credit","Nothing"],"correct":1,"re":"Unpaid final wages can cost up to 30 days of the worker's daily pay as a penalty."},
  {"id":221,"sec":"Public Works","secNum":6,"block":3,"q":"A public works project must be registered with the DIR using form:","opts":["DAS-140","PWC-100","DE 34","CF-1R"],"correct":1,"re":"The awarding body registers the project via PWC-100 with the DIR."},
  {"id":222,"sec":"Public Works","secNum":6,"block":3,"q":"On public works, a contractor notifies apprenticeship committees of a contract award using:","opts":["DAS-140","DAS-142","DE 542","CF-3R"],"correct":0,"re":"Form DAS-140 gives notice of the contract award to applicable apprenticeship committees."},
  {"id":223,"sec":"Public Works","secNum":6,"block":3,"q":"To request dispatch of apprentices on a public works job, a contractor submits:","opts":["DAS-140","DAS-142","PWC-100","Form 940"],"correct":1,"re":"Form DAS-142 requests dispatch of apprentices from the committee."},
  {"id":224,"sec":"Public Works","secNum":6,"block":3,"q":"Prevailing wage generally applies to public works contracts over:","opts":["$1,000","$15,000","$25,000","$100,000"],"correct":0,"re":"Prevailing wage applies to public works of more than $1,000 (with limited registration exemptions for small jobs)."},
  {"id":225,"sec":"Public Works","secNum":6,"block":3,"q":"The apprentice-to-journeyman work-hour ratio on public works is generally not less than:","opts":["1 apprentice hour per 5 journeyman hours","1 per 2","1 per 10","No ratio"],"correct":0,"re":"Public works generally require at least 1 hour of apprentice work for every 5 hours of journeyman work."},
  {"id":226,"sec":"Public Works","secNum":6,"block":3,"q":"Prevailing wage determinations are based on the:","opts":["Federal minimum wage","Basic hourly rate plus employer fringe-benefit payments by craft and locality","Contractor's choice","Union dues"],"correct":1,"re":"Determinations set the basic rate plus fringe contributions for each craft and area."},
  {"id":227,"sec":"Public Works","secNum":6,"block":3,"q":"Willful violation of prevailing wage law can result in debarment from public works for:","opts":["30 days","1 to 3 years","10 years","Permanently only"],"correct":1,"re":"Willful violations can bring debarment of 1 to 3 years (longer for repeat/serious cases)."},
  {"id":228,"sec":"Public Works","secNum":6,"block":3,"q":"Certified payroll on public works is filed electronically through:","opts":["The IRS portal","The DIR eCPR system","CSLB","The county recorder"],"correct":1,"re":"Contractors submit certified payroll records through the DIR's electronic eCPR system."},
  {"id":229,"sec":"Public Works","secNum":6,"block":3,"q":"On public works, overtime is owed based on:","opts":["Only after 40 hours/week","The hours specified in the applicable prevailing wage determination (often after 8/day)","Never","The contractor's policy"],"correct":1,"re":"PW overtime follows the determination — commonly after 8 hours/day and on weekends/holidays."},
  {"id":230,"sec":"Public Works","secNum":6,"block":3,"q":"Travel and subsistence pay on public works is:","opts":["Never owed","Owed when specified in the prevailing wage determination","Always double time","Paid by the worker"],"correct":1,"re":"Travel/subsistence is owed when the applicable determination requires it."},
  {"id":231,"sec":"Org & Licensing","secNum":1,"block":3,"q":"Title 24 of the California Code of Regulations is the:","opts":["Tax code","California Building Standards Code (incl. energy and mechanical)","Labor code","Vehicle code"],"correct":1,"re":"Title 24 is the Building Standards Code, covering energy (Part 6), mechanical (Part 4), CALGreen (Part 11), and more."},
  {"id":232,"sec":"Org & Licensing","secNum":1,"block":3,"q":"A building permit for an HVAC changeout in California is generally:","opts":["Not required","Required, and the licensed contractor typically pulls it","Pulled only by the owner","Optional"],"correct":1,"re":"Most HVAC changeouts require a permit; the licensed contractor usually pulls it for the work they perform."},
  {"id":233,"sec":"Org & Licensing","secNum":1,"block":3,"q":"Under Title 24 energy compliance, the certificate of compliance for a project is the:","opts":["CF-1R","CF-2R","CF-3R","DAS-140"],"correct":0,"re":"CF-1R is the Certificate of Compliance; CF-2R is installation; CF-3R is HERS field verification."},
  {"id":234,"sec":"Org & Licensing","secNum":1,"block":3,"q":"A HERS rater on a residential HVAC job typically verifies:","opts":["The bond","Duct leakage and refrigerant charge / airflow","The contract price","Payroll"],"correct":1,"re":"HERS verification confirms items like duct leakage and refrigerant charge/airflow per Title 24."},
  {"id":235,"sec":"Org & Licensing","secNum":1,"block":3,"q":"Performing permitted work without calling for the required final inspection means the job is:","opts":["Legally complete","Not properly completed and may violate code","Exempt from Title 24","Automatically approved"],"correct":1,"re":"Without the required inspections/final sign-off, the work isn't properly completed under code."},
  {"id":236,"sec":"Org & Licensing","secNum":1,"block":3,"q":"Doing work that requires a permit without obtaining one can result in:","opts":["A discount","Double permit fees and possible disciplinary action","A tax credit","Nothing"],"correct":1,"re":"Permit-required work done without a permit often incurs penalty (e.g., double) fees and CSLB exposure."},
  {"id":237,"sec":"Org & Licensing","secNum":1,"block":3,"q":"The California Mechanical Code is found in Title 24, Part:","opts":["Part 2","Part 4","Part 6","Part 11"],"correct":1,"re":"Part 4 is the California Mechanical Code; Part 6 is Energy; Part 11 is CALGreen."},
  {"id":238,"sec":"Org & Licensing","secNum":1,"block":3,"q":"An RMO/RME may generally serve as the qualifier for:","opts":["Unlimited firms","Only one firm at a time (with narrow ownership-based exceptions)","Exactly three firms","Only public agencies"],"correct":1,"re":"A qualifier is generally limited to one license, with narrow exceptions for commonly-owned firms."},
  {"id":239,"sec":"Org & Licensing","secNum":1,"block":3,"q":"A license not renewed by its expiration date may be renewed late, but with a:","opts":["No penalty","Delinquent renewal penalty (e.g., 50% of the fee)","Permanent ban","New exam"],"correct":1,"re":"Late renewal carries a delinquency penalty (commonly half the renewal fee) for a limited period."},
  {"id":240,"sec":"Org & Licensing","secNum":1,"block":3,"q":"Changing the business entity (e.g., sole prop to corporation) generally requires:","opts":["No action","A new license for the new entity","Just a name change form","Only a bond increase"],"correct":1,"re":"A different legal entity needs its own license; you can't transfer a license between entities."},
  {"id":241,"sec":"Contracts","secNum":5,"block":3,"q":"A person who sells home improvement contracts for a contractor in the field must register as a:","opts":["Notary","Home Improvement Salesperson (HIS)","Real estate agent","Public adjuster"],"correct":1,"re":"Home Improvement Salespersons must be registered with the CSLB."},
  {"id":242,"sec":"Contracts","secNum":5,"block":3,"q":"A home improvement contract must include:","opts":["Only a total price","Approximate start and completion dates and a payment schedule","The architect's seal","The lender's logo"],"correct":1,"re":"HICs must state approximate start/completion dates, the price, and a work-based payment schedule."},
  {"id":243,"sec":"Contracts","secNum":5,"block":3,"q":"An arbitration clause in a home improvement contract generally must be:","opts":["Hidden in fine print","Clearly disclosed and separately initialed/agreed","Verbal only","Omitted"],"correct":1,"re":"Mandatory arbitration provisions in consumer HICs must be conspicuously disclosed and acknowledged."},
  {"id":244,"sec":"Contracts","secNum":5,"block":3,"q":"The notice of the three-day right to cancel must be:","opts":["Mentioned verbally","Attached to the contract with cancellation forms","Filed with CSLB","Posted online"],"correct":1,"re":"The buyer must receive the cancellation notice and forms with the contract."},
  {"id":245,"sec":"Contracts","secNum":5,"block":3,"q":"Accepting an excessive down payment on a home improvement contract is:","opts":["Allowed if the customer agrees","A violation of the license law","Standard practice","Required by lenders"],"correct":1,"re":"Exceeding the down-payment cap is a violation, even with the customer's consent."},
  {"id":246,"sec":"Contracts","secNum":5,"block":3,"q":"'Substantial commencement' of work means the contractor must:","opts":["Just sign the contract","Make a genuine beginning and diligently prosecute the work","Wait for full payment","Order materials only"],"correct":1,"re":"After taking a deposit, the contractor must substantially begin and diligently pursue the work."},
  {"id":247,"sec":"Contracts","secNum":5,"block":3,"q":"A 'funding control' (joint control) service on a project is used to:","opts":["Set prices","Disburse construction funds as work progresses to protect against diversion","Pull permits","File liens"],"correct":1,"re":"Joint/funding control releases payments per progress, reducing the risk of misused funds."},
  {"id":248,"sec":"Contracts","secNum":5,"block":3,"q":"A contractor may NOT include in a consumer contract a clause that:","opts":["States the price","Waives the buyer's statutory cancellation rights in advance","Lists materials","Sets a schedule"],"correct":1,"re":"Advance waivers of mandatory consumer protections (like cancellation rights) are unenforceable."},
  {"id":249,"sec":"Contracts","secNum":5,"block":3,"q":"For a swimming pool home improvement contract, the down-payment and progress rules are:","opts":["Identical to all HICs","Subject to specific statutory schedule limits","Unregulated","Set by the lender"],"correct":1,"re":"Pool contracts have their own statutory payment-schedule and down-payment provisions."},
  {"id":250,"sec":"Contracts","secNum":5,"block":3,"q":"A change order on a fixed-price contract should be:","opts":["Verbal","In writing, signed, stating scope, price, and time impact","Ignored","Filed with the state"],"correct":1,"re":"Written, signed change orders prevent disputes by documenting the new scope, cost, and schedule."},
  {"id":251,"sec":"Business Finances","secNum":2,"block":3,"q":"The 'quick ratio' (acid-test) differs from the current ratio because it excludes:","opts":["Cash","Inventory","Receivables","Payables"],"correct":1,"re":"The quick ratio strips out inventory to test immediate liquidity."},
  {"id":252,"sec":"Business Finances","secNum":2,"block":3,"q":"A high debt-to-equity ratio generally signals:","opts":["Low risk","Heavier reliance on borrowed money","More cash","Lower overhead"],"correct":1,"re":"Debt-to-equity over a healthy range indicates greater leverage and risk."},
  {"id":253,"sec":"Business Finances","secNum":2,"block":3,"q":"Straight-line depreciation of a $30,000 asset with a 10-year life and no salvage is:","opts":["$1,000/yr","$3,000/yr","$6,000/yr","$30,000/yr"],"correct":1,"re":"$30,000 ÷ 10 years = $3,000 per year."},
  {"id":254,"sec":"Business Finances","secNum":2,"block":3,"q":"A contractor's bonding capacity is most closely tied to its:","opts":["Truck count","Working capital and net worth","Advertising budget","Number of permits"],"correct":1,"re":"Sureties size bonding capacity largely off working capital and net worth."},
  {"id":255,"sec":"Business Finances","secNum":2,"block":3,"q":"'Labor burden' refers to:","opts":["Base wages only","Payroll taxes, workers' comp, and benefits added on top of wages","Overtime only","Materials"],"correct":1,"re":"Labor burden is the added cost of taxes, WC, and benefits on top of base wages."},
  {"id":256,"sec":"Business Finances","secNum":2,"block":3,"q":"A 'contingency' line in an estimate is meant to cover:","opts":["Profit","Unforeseen costs and risk","Marketing","Owner's salary"],"correct":1,"re":"Contingency cushions the estimate against unknowns and risk."},
  {"id":257,"sec":"Business Finances","secNum":2,"block":3,"q":"Large construction contractors are often required for tax to use:","opts":["Cash basis only","Accrual / percentage-of-completion","No method","Completed-contract always"],"correct":1,"re":"Above IRS thresholds, contractors typically must use accrual and percentage-of-completion."},
  {"id":258,"sec":"Business Finances","secNum":2,"block":3,"q":"'Job costing' means:","opts":["One total for all jobs","Tracking labor, materials, and overhead per individual project","Only tracking taxes","Estimating annually"],"correct":1,"re":"Job costing assigns direct and allocated costs to each project to measure profitability."},
  {"id":259,"sec":"Business Finances","secNum":2,"block":3,"q":"Retainage withheld from a subcontractor is best recorded as:","opts":["Immediate expense","A payable released upon completion","Revenue","Owner's draw"],"correct":1,"re":"Retention owed to a sub is a liability (payable) until released at completion."},
  {"id":260,"sec":"Business Finances","secNum":2,"block":3,"q":"If overhead is $120,000 and gross margin is 30%, sales needed just to cover overhead are:","opts":["$120,000","$300,000","$400,000","$36,000"],"correct":2,"re":"$120,000 ÷ 0.30 = $400,000 in sales to cover overhead at a 30% margin."},
  {"id":261,"sec":"Org & Licensing","secNum":1,"block":3,"q":"A California LLC contractor must carry liability insurance of at least:","opts":["$50,000","$100,000 with $1,000,000 aggregate (rising with added personnel, up to $5M)","$25,000","None"],"correct":1,"re":"LLC licensees must maintain liability insurance ($1M aggregate, increasing with personnel up to $5M) plus the worker bond."},
  {"id":262,"sec":"Org & Licensing","secNum":1,"block":3,"q":"A California LLC contractor must also post a separate bond for the benefit of:","opts":["The owner","Employees/workers ($100,000)","Suppliers only","The lender"],"correct":1,"re":"LLCs must file a $100,000 bond protecting employees and workers, separate from the $25,000 contractor bond."},
  {"id":263,"sec":"Org & Licensing","secNum":1,"block":3,"q":"California requires contractor applicants to submit:","opts":["A college diploma","Fingerprints (Live Scan) for a background check","A union card","A federal license"],"correct":1,"re":"Applicants must submit fingerprints via Live Scan for criminal background review."},
  {"id":264,"sec":"Org & Licensing","secNum":1,"block":3,"q":"To qualify for a C-20 (or most classifications), an applicant must show:","opts":["No experience","At least 4 years of journey-level experience (or equivalent)","10 years always","Only a passing exam"],"correct":1,"re":"Applicants generally need 4 years of qualifying journey-level experience within the past 10."},
  {"id":265,"sec":"Org & Licensing","secNum":1,"block":3,"q":"California requires contractors to complete continuing education to renew:","opts":["Yes, 30 hours","No — there is no general CE requirement for contractor renewal","Only for C-20","Only for general B"],"correct":1,"re":"California does not impose general continuing-education for contractor license renewal."},
  {"id":266,"sec":"Insurance & Liens","secNum":4,"block":3,"q":"On a FEDERAL public project, unpaid subs/suppliers are protected by the:","opts":["California Mechanics Lien Law","Miller Act payment bond","Title 24","CSLB bond"],"correct":1,"re":"The federal Miller Act requires payment bonds protecting subs/suppliers on federal projects."},
  {"id":267,"sec":"Insurance & Liens","secNum":4,"block":3,"q":"A surety bond differs from insurance because, after paying a claim, the surety:","opts":["Absorbs the loss","Seeks reimbursement from the contractor (principal)","Cancels the license","Pays the owner forever"],"correct":1,"re":"A bond is a three-party guarantee; the surety can recover what it pays from the principal."},
  {"id":268,"sec":"Insurance & Liens","secNum":4,"block":3,"q":"In a surety bond, the three parties are the principal, the obligee, and the:","opts":["Lender","Surety","Architect","Inspector"],"correct":1,"re":"The surety guarantees the principal's obligation to the obligee."},
  {"id":269,"sec":"Insurance & Liens","secNum":4,"block":3,"q":"A bid bond is typically issued for what portion of the bid?","opts":["1%","About 10%","50%","100%"],"correct":1,"re":"Bid bonds are commonly around 10% of the bid amount."},
  {"id":270,"sec":"Insurance & Liens","secNum":4,"block":3,"q":"A material supplier preserving lien rights must serve a preliminary notice within 20 days of:","opts":["Delivery completion","First delivering materials to the site","The lawsuit","Recording the lien"],"correct":1,"re":"The 20-day clock runs from first furnishing materials to the project."},
  {"id":271,"sec":"Safety","secNum":7,"block":3,"q":"A C-20 applicant must hold which EPA certification to handle refrigerants?","opts":["Type I only","An applicable EPA Section 608 certification (often Universal)","OSHA 30","None"],"correct":1,"re":"Refrigerant handling requires EPA 608 certification; Universal covers all system types."},
  {"id":272,"sec":"Safety","secNum":7,"block":3,"q":"An attic or crawlspace during HVAC service may qualify as a:","opts":["Public space","Confined space requiring hazard assessment","Scaffold","Trench"],"correct":1,"re":"Restricted-access areas like attics/crawlspaces can be confined spaces needing assessment."},
  {"id":273,"sec":"Safety","secNum":7,"block":3,"q":"Before servicing energized HVAC equipment, the technician should:","opts":["Work it live","Apply lockout/tagout to control hazardous energy","Remove guards","Skip PPE"],"correct":1,"re":"LOTO de-energizes and secures equipment to prevent unexpected startup during service."},
  {"id":274,"sec":"Safety","secNum":7,"block":3,"q":"A straight (non-self-supporting) ladder should be set at a base-to-height ratio of about:","opts":["1:1","1:4","1:8","1:20"],"correct":1,"re":"The 4:1 rule: base out 1 foot for every 4 feet of working height."},
  {"id":275,"sec":"Safety","secNum":7,"block":3,"q":"Cal/OSHA's Form 300A annual summary must be posted from:","opts":["Jan 1–Mar 1","February 1 through April 30","July 1–Aug 1","Year-round"],"correct":1,"re":"The 300A summary is posted February 1 through April 30 each year."},
  {"id":276,"sec":"Safety","secNum":7,"block":3,"q":"High-heat procedures under Cal/OSHA's heat standard generally apply at or above:","opts":["80°F","85°F","95°F","110°F"],"correct":2,"re":"High-heat procedures (extra observation, reminders) kick in at 95°F for specified industries."},
  {"id":277,"sec":"Safety","secNum":7,"block":3,"q":"Shade for rest must be available under the heat standard when temperature reaches:","opts":["70°F","80°F","100°F","Never"],"correct":1,"re":"Access to shade must be provided when the temperature exceeds 80°F."},
  {"id":278,"sec":"Safety","secNum":7,"block":3,"q":"Hearing protection/conservation is generally required when noise reaches an 8-hour average of:","opts":["65 dB","85 dB","105 dB","130 dB"],"correct":1,"re":"A hearing conservation program is triggered at an 8-hour TWA of 85 dB."},
  {"id":279,"sec":"Safety","secNum":7,"block":3,"q":"Cutting/grinding masonry that generates dust implicates Cal/OSHA's standard for:","opts":["Lead","Respirable crystalline silica","Asbestos only","Noise"],"correct":1,"re":"Dust from concrete/masonry triggers the respirable crystalline silica standard."},
  {"id":280,"sec":"Safety","secNum":7,"block":3,"q":"Reporting a work-related amputation or in-patient hospitalization to Cal/OSHA is required within:","opts":["8 hours","24 hours","72 hours","1 week"],"correct":0,"re":"Serious outcomes — fatalities, amputations, in-patient hospitalization — are reported within 8 hours."},
  {"id":281,"sec":"Contracts","secNum":5,"block":3,"q":"A contractor's failure to substantially commence work after taking a deposit may be:","opts":["Permitted","A statutory violation (abandonment) subject to discipline","A change order","A lien"],"correct":1,"re":"Taking a deposit then failing to begin/diligently pursue is disciplinable abandonment."},
  {"id":282,"sec":"Contracts","secNum":5,"block":3,"q":"A 'mechanics lien warning' in a HIC informs the owner that:","opts":["The price may change","Unpaid subs/suppliers could lien the home even if the owner paid the contractor","Permits are optional","The bond is void"],"correct":1,"re":"It warns that unpaid subs/suppliers may lien the property despite the owner paying the prime."},
  {"id":283,"sec":"Contracts","secNum":5,"block":3,"q":"A contractor who diverts funds paid for a specific project to other uses, harming the project, may face:","opts":["No issue","Discipline for diversion of funds","A tax credit","A bonus"],"correct":1,"re":"Diverting project funds (so the job suffers) is a statutory ground for discipline."},
  {"id":284,"sec":"Contracts","secNum":5,"block":3,"q":"An 'as-built' set of documents reflects:","opts":["The original bid","The work as actually constructed, including changes","The warranty","The lien"],"correct":1,"re":"As-builts document the final constructed condition with all field changes."},
  {"id":285,"sec":"Contracts","secNum":5,"block":3,"q":"A contractor's bid is generally considered a(n):","opts":["Binding contract","Offer that becomes a contract upon acceptance","Warranty","Lien"],"correct":1,"re":"A bid is an offer; acceptance by the owner forms the contract."},
  {"id":286,"sec":"Insurance & Liens","secNum":4,"block":3,"q":"'Completion' for lien-deadline purposes can be triggered by actual completion or by:","opts":["The bid date","Cessation of labor for a continuous statutory period, or acceptance/occupation","Permit issuance","First delivery"],"correct":1,"re":"Completion can also be deemed at acceptance, occupation/use, or a continuous cessation of labor."},
  {"id":287,"sec":"Insurance & Liens","secNum":4,"block":3,"q":"A design professional (e.g., architect) who is unpaid may, before construction, use a:","opts":["Mechanics lien only","Design professional's lien under specific conditions","Stop notice only","Bid bond"],"correct":1,"re":"Unpaid design professionals have a limited statutory design professional's lien remedy."},
  {"id":288,"sec":"Insurance & Liens","secNum":4,"block":3,"q":"To dispute a recorded lien, an owner can compel the claimant to act by:","opts":["Ignoring it","Demanding the claimant file suit (or release) within a shortened period","Paying double","Filing a permit"],"correct":1,"re":"An owner can serve a demand forcing the claimant to enforce or release the lien on a shortened timeline."},
  {"id":289,"sec":"Public Works","secNum":6,"block":3,"q":"A 'skilled and trained workforce' requirement on certain public works mandates:","opts":["Only union labor","A percentage of work hours by skilled journeypersons (often apprenticeship graduates)","No apprentices","Lowest bidder only"],"correct":1,"re":"It requires set percentages of hours performed by skilled journeypersons, many apprenticeship-trained."},
  {"id":290,"sec":"Public Works","secNum":6,"block":3,"q":"A payment bond is generally required on California public works contracts over:","opts":["$1,000","$5,000","$25,000","$1,000,000"],"correct":2,"re":"Public works payment bonds are generally required when the contract exceeds $25,000."},
  {"id":291,"sec":"Employment","secNum":3,"block":3,"q":"Paying a worker a day rate that, divided by hours, falls below minimum wage is:","opts":["Allowed","A wage violation","Fine if agreed","Only an issue for OT"],"correct":1,"re":"Effective pay below minimum wage for hours worked is a violation regardless of pay structure."},
  {"id":292,"sec":"Employment","secNum":3,"block":3,"q":"On the 7th consecutive workday, hours OVER 8 are paid at:","opts":["Straight time","1.5×","2×","No premium"],"correct":2,"re":"Beyond 8 hours on the 7th consecutive day, pay is double time."},
  {"id":293,"sec":"Employment","secNum":3,"block":3,"q":"Misclassifying employees to avoid workers' comp can lead to:","opts":["Nothing","Stop orders, penalties, and possible criminal charges","A refund","A license upgrade"],"correct":1,"re":"Avoiding WC via misclassification can bring stop orders, steep penalties, and criminal exposure."},
  {"id":294,"sec":"Business Finances","secNum":2,"block":3,"q":"If material cost is $2,400 and you apply a 35% markup, the price is:","opts":["$3,000","$3,240","$3,360","$3,692"],"correct":1,"re":"$2,400 × 1.35 = $3,240."},
  {"id":295,"sec":"Business Finances","secNum":2,"block":3,"q":"A profit margin of 20% on a $50,000 job means profit of:","opts":["$5,000","$10,000","$12,500","$20,000"],"correct":1,"re":"20% of $50,000 = $10,000 profit."},
  {"id":296,"sec":"Org & Licensing","secNum":1,"block":3,"q":"A contractor's advertising that omits the license number is:","opts":["Fine","A violation of the license law","Required by lenders","Only an issue online"],"correct":1,"re":"Licensed contractors must display their license number in all advertising."},
  {"id":297,"sec":"Org & Licensing","secNum":1,"block":3,"q":"An applicant who has the experience but cannot pass the exam:","opts":["Gets the license anyway","Cannot be licensed until passing the required exams","Can buy the license","Is exempt"],"correct":1,"re":"Both qualifying experience and passing the law and trade exams are required for licensure."},
  {"id":298,"sec":"Contracts","secNum":5,"block":3,"q":"Oral modifications to a contract with an integration clause are:","opts":["Always binding","Often unenforceable; changes should be written","Required","Illegal"],"correct":1,"re":"With an integration clause, rely on written, signed changes rather than oral promises."},
  {"id":299,"sec":"Contracts","secNum":5,"block":3,"q":"A contractor who substantially performs but leaves minor punch-list items is generally entitled to:","opts":["Nothing","The contract price less the cost to complete the minor items","Double payment","A lien only"],"correct":1,"re":"Substantial performance allows recovery of the price minus the cost to fix minor remaining items."},
  {"id":300,"sec":"Safety","secNum":7,"block":3,"q":"The foundation of Cal/OSHA compliance for any contractor is a functioning:","opts":["Bond","Injury and Illness Prevention Program (IIPP)","Marketing plan","Lien log"],"correct":1,"re":"A working, written IIPP is the cornerstone of Cal/OSHA compliance."},
  {"id":301,"sec":"Org & Licensing","secNum":1,"block":4,"q":"Diverting funds received for a specific construction project to another use, harming that project, is a violation under B&P Code:","opts":["§7068","§7107","§7159","§7200"],"correct":1,"re":"§7107 makes diversion of project funds a ground for discipline."},
  {"id":302,"sec":"Org & Licensing","secNum":1,"block":4,"q":"Willful departure from accepted trade standards or from plans/specs, causing harm, is disciplinable under:","opts":["§7109","§7114","§7120","§7058.5"],"correct":0,"re":"§7109 covers willful departure from plans/specs or accepted trade standards."},
  {"id":303,"sec":"Org & Licensing","secNum":1,"block":4,"q":"Aiding or abetting an unlicensed person to evade the license law violates:","opts":["§7107","§7110","§7114","§7123"],"correct":2,"re":"§7114 prohibits aiding unlicensed activity."},
  {"id":304,"sec":"Org & Licensing","secNum":1,"block":4,"q":"Willful violation of building, safety, labor, or wage laws by a contractor is a ground for discipline under:","opts":["§7110","§7116","§7159","§7065"],"correct":0,"re":"§7110 covers willful violation of building/safety/labor/compensation laws."},
  {"id":305,"sec":"Org & Licensing","secNum":1,"block":4,"q":"Fraud or willful misrepresentation in obtaining a license or in performing work is disciplinable under:","opts":["§7068","§7116","§7120","§7200"],"correct":1,"re":"§7116 addresses fraud or willful misrepresentation."},
  {"id":306,"sec":"Org & Licensing","secNum":1,"block":4,"q":"Willful failure to pay for materials or services rendered, when able, is a ground for discipline under:","opts":["§7120","§7107","§7114","§7058"],"correct":0,"re":"§7120 covers willful failure to pay for materials or services."},
  {"id":307,"sec":"Org & Licensing","secNum":1,"block":4,"q":"Abandoning a project without legal excuse, or failing to complete for the contracted price, is disciplinable under:","opts":["§7113","§7065","§7159","§7137"],"correct":0,"re":"§7113 addresses failure to complete for the agreed price / abandonment."},
  {"id":308,"sec":"Org & Licensing","secNum":1,"block":4,"q":"A CSLB disciplinary action for a patent (obvious) defect must generally begin within how many years of the act?","opts":["1","2","4","10"],"correct":2,"re":"For patent acts, the limitations period for CSLB action is generally 4 years."},
  {"id":309,"sec":"Org & Licensing","secNum":1,"block":4,"q":"For a latent (hidden) defect, the CSLB limitations period to act is generally:","opts":["4 years","10 years","No limit","1 year"],"correct":1,"re":"Latent-defect discipline generally must begin within 10 years."},
  {"id":310,"sec":"Org & Licensing","secNum":1,"block":4,"q":"After a license is revoked, the contractor generally may not apply for reinstatement or a new license for at least:","opts":["30 days","1 year","5 years","Permanently"],"correct":1,"re":"A revoked licensee generally cannot reapply for at least one year (longer in some cases)."},
  {"id":311,"sec":"Org & Licensing","secNum":1,"block":4,"q":"A CSLB 'citation' may impose an order of correction and a civil penalty without:","opts":["Any notice","A full Administrative Procedure Act hearing","Any violation","The contractor's knowledge"],"correct":1,"re":"A citation resolves matters with correction/penalty short of a full disciplinary hearing (the contractor may appeal)."},
  {"id":312,"sec":"Org & Licensing","secNum":1,"block":4,"q":"California's CSLB consumer remedy structure notably does NOT include:","opts":["The contractor's bond","Mandatory/voluntary arbitration","A state recovery fund (like some other states)","Civil court action"],"correct":2,"re":"California has no contractor recovery fund; consumers use the bond, arbitration, or court."},
  {"id":313,"sec":"Org & Licensing","secNum":1,"block":4,"q":"CSLB mandatory arbitration of a complaint generally applies to disputes up to:","opts":["$1,000","$15,000","$50,000","$100,000"],"correct":1,"re":"Mandatory CSLB arbitration generally covers disputes up to $15,000; voluntary up to $50,000."},
  {"id":314,"sec":"Org & Licensing","secNum":1,"block":4,"q":"A formal disciplinary proceeding before the CSLB is governed by the:","opts":["Penal Code","Administrative Procedure Act","Vehicle Code","UCC"],"correct":1,"re":"CSLB disciplinary hearings follow the Administrative Procedure Act."},
  {"id":315,"sec":"Org & Licensing","secNum":1,"block":4,"q":"A conviction of a crime substantially related to the qualifications/duties of a contractor can be grounds for:","opts":["A bonus","Denial or discipline of a license","Automatic renewal","Nothing"],"correct":1,"re":"Substantially-related convictions can support license denial or discipline."},
  {"id":316,"sec":"Org & Licensing","secNum":1,"block":4,"q":"To impose discipline, the CSLB must generally prove violations by:","opts":["Beyond a reasonable doubt","Clear and convincing evidence (to a reasonable certainty)","A coin flip","Nothing"],"correct":1,"re":"Professional discipline typically requires clear and convincing evidence."},
  {"id":317,"sec":"Org & Licensing","secNum":1,"block":4,"q":"If a contractor's bond claim is paid out, the contractor must usually:","opts":["Do nothing","Reinstate/replace the bond to keep the license active","Surrender the license","Double the bond forever"],"correct":1,"re":"After a bond payout, the contractor must restore bonding to maintain an active license."},
  {"id":318,"sec":"Safety","secNum":7,"block":4,"q":"All new license applicants must pass the CSLB asbestos open-book examination under B&P Code:","opts":["§7058.5","§7068","§7159","§7110"],"correct":0,"re":"§7058.5 requires the asbestos open-book exam before licensure (it does not certify asbestos work)."},
  {"id":319,"sec":"Safety","secNum":7,"block":4,"q":"To perform asbestos-related work above the regulatory threshold, a contractor must additionally hold:","opts":["Only a C-20","An asbestos certification (registration with Cal/OSHA DOSH) and pass a cert exam","Nothing extra","A real estate license"],"correct":1,"re":"Asbestos-related work requires a separate asbestos certification and Cal/OSHA registration."},
  {"id":320,"sec":"Safety","secNum":7,"block":4,"q":"The stand-alone CSLB classification specifically for asbestos abatement is:","opts":["C-20","C-22","C-36","B"],"correct":1,"re":"C-22 is the Asbestos Abatement classification; it stands alone."},
  {"id":321,"sec":"Safety","secNum":7,"block":4,"q":"Cal/OSHA asbestos registration is generally required when the work involves more than:","opts":["10 sq ft / linear ft","100 sq ft or 100 linear ft of asbestos-containing material","1,000 sq ft","Any amount"],"correct":1,"re":"Registration is required above 100 sq ft / 100 linear ft of ACM."},
  {"id":322,"sec":"Safety","secNum":7,"block":4,"q":"Before certain demolition/renovation, federal NESHAP rules require notifying the air district at least:","opts":["1 day","10 working days in advance","30 days after","Never"],"correct":1,"re":"NESHAP generally requires a 10-working-day advance notification for regulated demolition/renovation."},
  {"id":323,"sec":"Safety","secNum":7,"block":4,"q":"Lead-related construction work (e.g., disturbing lead paint) in California requires workers to be:","opts":["Unrestricted","Certified/trained for lead-related work (CDPH) with proper controls","C-22 only","EPA 608 certified"],"correct":1,"re":"Lead work requires CDPH lead certification/training and engineering controls."},
  {"id":324,"sec":"Safety","secNum":7,"block":4,"q":"Removal of hazardous substances (HAZ certification) is available only to contractors who first hold:","opts":["Any C license","Specified classifications (A, B, C-36, C-12, C-57, etc.) plus a cert exam","No license","A C-20 only"],"correct":1,"re":"HAZ certification overlays specified base classifications and requires passing a certification exam."},
  {"id":325,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"On a private project, a 'bonded stop payment notice' from a subcontractor:","opts":["Has no effect","Compels the lender to withhold funds (priority over an unbonded notice)","Replaces the lien","Is illegal"],"correct":1,"re":"A bonded stop payment notice can force a construction lender to withhold funds and takes priority."},
  {"id":326,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"Mechanics lien priority generally 'relates back' to:","opts":["The lien recording date","The date work first commenced on the project","The completion date","The permit date"],"correct":1,"re":"Lien priority typically relates back to commencement of the work of improvement."},
  {"id":327,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"A laborer who personally performed work generally:","opts":["Must serve a 20-day notice like suppliers","Has lien rights without serving a preliminary notice","Has no lien rights","Must record within 10 days"],"correct":1,"re":"Laborers' wage claims are generally exempt from the preliminary notice requirement."},
  {"id":328,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"On a FEDERAL project, a second-tier claimant under the Miller Act must give notice to the prime within:","opts":["20 days","90 days of last furnishing","1 year","No notice"],"correct":1,"re":"Miller Act second-tier claimants must notify the prime within 90 days of last furnishing labor/materials."},
  {"id":329,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"A Miller Act payment bond suit must generally be filed within:","opts":["90 days","6 months","1 year of last furnishing","4 years"],"correct":2,"re":"Suit on a Miller Act payment bond must be brought within one year of last furnishing."},
  {"id":330,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"A design professional's lien (for architects/engineers) generally applies:","opts":["After completion","Before construction begins, for unpaid pre-construction services, under conditions","Only on public works","Never"],"correct":1,"re":"It provides limited recovery for unpaid pre-construction design services under set conditions."},
  {"id":331,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"A lender's construction loan recorded BEFORE work commences generally has priority over:","opts":["Nothing","Later mechanics liens (because liens relate back to commencement)","The owner","Property taxes"],"correct":1,"re":"A deed of trust recorded before any work has priority because liens relate back to commencement."},
  {"id":332,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"A claimant who over-states a lien in bad faith may:","opts":["Recover more","Lose the lien and face liability","Get a bonus","Face nothing"],"correct":1,"re":"A willfully exaggerated lien can be void and expose the claimant to damages."},
  {"id":333,"sec":"Org & Licensing","secNum":1,"block":4,"q":"Operating with a suspended license is:","opts":["Permitted briefly","Treated like unlicensed contracting (a violation)","Allowed for existing jobs","Only a paperwork issue"],"correct":1,"re":"Contracting while suspended is treated as unlicensed activity."},
  {"id":334,"sec":"Org & Licensing","secNum":1,"block":4,"q":"If a qualifier leaves and is not replaced within the statutory window, the license is:","opts":["Unaffected","Automatically suspended","Upgraded","Transferred"],"correct":1,"re":"Failing to replace the qualifier in time results in suspension."},
  {"id":335,"sec":"Contracts","secNum":5,"block":4,"q":"A contractor who substantially overcharges compared to a reasonable price ('excessive price') may face:","opts":["Nothing","Discipline where statute defines it as a violation (e.g., disaster price gouging)","A bonus","A tax credit"],"correct":1,"re":"Excessive pricing in defined contexts (e.g., declared emergencies) can be a violation."},
  {"id":336,"sec":"Contracts","secNum":5,"block":4,"q":"During a declared state of emergency, raising prices on many goods/services beyond a set percentage is:","opts":["Allowed","Prohibited price gouging (commonly capped near 10%)","Encouraged","Only a civil matter"],"correct":1,"re":"Penal Code §396 caps most price increases (commonly ~10%) during declared emergencies."},
  {"id":337,"sec":"Org & Licensing","secNum":1,"block":4,"q":"A contractor must report to CSLB a felony or specified misdemeanor conviction because:","opts":["It's optional","Nondisclosure can itself be a violation","CSLB never checks","Only DUIs matter"],"correct":1,"re":"Licensees must disclose certain convictions; concealment is independently disciplinable."},
  {"id":338,"sec":"Safety","secNum":7,"block":4,"q":"A contractor disturbing painted surfaces in a pre-1978 home should assume the presence of:","opts":["Asbestos only","Lead-based paint (until tested otherwise)","Nothing","Mold only"],"correct":1,"re":"Pre-1978 housing is presumed to contain lead-based paint absent testing."},
  {"id":339,"sec":"Safety","secNum":7,"block":4,"q":"Improperly disposing of hazardous waste (e.g., refrigerant, solvents) can result in:","opts":["No issue","Environmental fines and liability","A tax credit","A CSLB bonus"],"correct":1,"re":"Illegal hazardous-waste disposal brings environmental penalties and liability."},
  {"id":340,"sec":"Safety","secNum":7,"block":4,"q":"Venting most HFC/HCFC refrigerants to the atmosphere during service is:","opts":["Allowed","Prohibited under EPA Section 608","Required","Only a state issue"],"correct":1,"re":"EPA §608 prohibits knowingly venting regulated refrigerants."},
  {"id":341,"sec":"Business Finances","secNum":2,"block":4,"q":"If a contractor's liabilities exceed assets, the business has:","opts":["Positive equity","Negative net worth (insolvency risk)","High liquidity","No overhead"],"correct":1,"re":"Liabilities over assets means negative equity and possible insolvency."},
  {"id":342,"sec":"Business Finances","secNum":2,"block":4,"q":"A surety evaluating bonding will look most closely at the 'three C's':","opts":["Cash, cars, contracts","Capital, capacity, character","Cost, color, county","Credit, clients, codes"],"correct":1,"re":"Sureties weigh capital, capacity, and character."},
  {"id":343,"sec":"Business Finances","secNum":2,"block":4,"q":"Underbilling on a percentage-of-completion job means the contractor has:","opts":["Billed more than earned","Billed less than the work completed (a current asset)","Overcharged","No work left"],"correct":1,"re":"Underbilling (costs in excess of billings) is recorded as a current asset."},
  {"id":344,"sec":"Employment","secNum":3,"block":4,"q":"An employer that retaliates against a worker for filing a wage claim may face:","opts":["Nothing","Penalties and reinstatement/back-pay liability","A tax credit","A bonus"],"correct":1,"re":"Retaliation for protected wage complaints is unlawful and brings penalties."},
  {"id":345,"sec":"Employment","secNum":3,"block":4,"q":"Cal/OSHA may issue an 'Order Prohibiting Use' to:","opts":["Cancel a license","Bar use of dangerous equipment/area until a hazard is corrected","Set wages","Approve a permit"],"correct":1,"re":"An OPU stops use of equipment/work areas posing imminent hazard until fixed."},
  {"id":346,"sec":"Safety","secNum":7,"block":4,"q":"An 'imminent hazard' under Cal/OSHA allows the agency to:","opts":["Do nothing","Order immediate abatement or shut down the operation","Wait a year","Issue a bonus"],"correct":1,"re":"Imminent hazards justify immediate abatement orders or shutdown."},
  {"id":347,"sec":"Contracts","secNum":5,"block":4,"q":"A 'waiver of subrogation' clause means an insurer agrees:","opts":["To double coverage","Not to pursue the other party after paying a claim","To cancel the policy","To pay liens"],"correct":1,"re":"It waives the insurer's right to recover from the named other party."},
  {"id":348,"sec":"Contracts","secNum":5,"block":4,"q":"An 'indemnification' clause requires one party to:","opts":["Pay taxes","Cover/defend the other against specified losses or claims","Buy materials","Pull permits"],"correct":1,"re":"Indemnity shifts responsibility for certain losses/claims to the indemnifying party."},
  {"id":349,"sec":"Contracts","secNum":5,"block":4,"q":"In California, an indemnity clause that shifts liability for the indemnitee's SOLE negligence is generally:","opts":["Fully enforceable","Void/unenforceable in construction contracts","Required","Tax-deductible"],"correct":1,"re":"Clauses indemnifying a party for its own sole negligence are void in construction contracts."},
  {"id":350,"sec":"Public Works","secNum":6,"block":4,"q":"A 'Notice of Completion' on a public works project affects:","opts":["Wages","The deadlines for stop payment notices and bond claims","The bid","The permit"],"correct":1,"re":"On public works, completion events shorten the windows for stop payment notices and bond claims."},
  {"id":351,"sec":"Public Works","secNum":6,"block":4,"q":"Falsely certifying skilled-and-trained-workforce compliance on public works is:","opts":["Minor","A serious violation with penalties","Encouraged","Allowed under $25k"],"correct":1,"re":"False compliance certifications expose the contractor to penalties and liability."},
  {"id":352,"sec":"Public Works","secNum":6,"block":4,"q":"DIR registration for public works must generally be:","opts":["One-time forever","Renewed (on a set cycle) and current to bid/work","Optional","Done after the job"],"correct":1,"re":"Contractors must keep DIR registration current to bid and perform public works."},
  {"id":353,"sec":"Org & Licensing","secNum":1,"block":4,"q":"A contractor advertising a specialty they are NOT licensed for commits:","opts":["Smart marketing","A license-law violation","A federal crime only","Nothing"],"correct":1,"re":"Advertising work outside your classification/without a license is a violation."},
  {"id":354,"sec":"Org & Licensing","secNum":1,"block":4,"q":"A 'home improvement' contractor classification question: HVAC changeouts on existing homes are typically performed under:","opts":["No license","A C-20 (with HIC rules applying to the contract)","A real estate license","A C-22"],"correct":1,"re":"HVAC work uses the C-20; home-improvement contract rules govern the consumer agreement."},
  {"id":355,"sec":"Contracts","secNum":5,"block":4,"q":"A contractor cannot enforce a contract clause requiring the consumer to:","opts":["Pay the price","Waive the right to a jury or statutory protections without clear, conspicuous disclosure","Provide access","Choose colors"],"correct":1,"re":"Hidden waivers of important rights are unenforceable; disclosure must be clear and conspicuous."},
  {"id":356,"sec":"Business Finances","secNum":2,"block":4,"q":"A 'liquidity' problem is best addressed by:","opts":["Buying more equipment","Improving cash flow (billing, collections, credit terms)","Hiring more","Lowering prices"],"correct":1,"re":"Liquidity improves through faster billing/collections and managed credit, not more spending."},
  {"id":357,"sec":"Business Finances","secNum":2,"block":4,"q":"A retention receivable of 10% on a $200,000 contract equals:","opts":["$2,000","$10,000","$20,000","$40,000"],"correct":2,"re":"10% of $200,000 = $20,000 held as retention."},
  {"id":358,"sec":"Employment","secNum":3,"block":4,"q":"An employee injured on the job should first:","opts":["Sue the employer","Report it and file a workers' comp claim","Quit","Call CSLB"],"correct":1,"re":"Job injuries go through the workers' comp system, starting with prompt reporting and a claim."},
  {"id":359,"sec":"Employment","secNum":3,"block":4,"q":"Workers' comp generally provides employees with:","opts":["Punitive damages","Medical care and wage-replacement benefits regardless of fault","A new job","Stock"],"correct":1,"re":"Workers' comp is no-fault: medical treatment and partial wage replacement."},
  {"id":360,"sec":"Safety","secNum":7,"block":4,"q":"Cal/OSHA penalties are typically higher for violations that are:","opts":["Accidental","Repeat, serious, or willful","First-time minor","Self-reported only"],"correct":1,"re":"Repeat, serious, and willful violations carry steeper penalties."},
  {"id":361,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"The contractor's $25,000 bond primarily protects:","opts":["The contractor","Homeowners, certain employees, and specified others from violations","The lender","The IRS"],"correct":1,"re":"The bond covers statutory claims by consumers, employees (wages), and certain others."},
  {"id":362,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"An employee wage claim against the contractor's bond is generally limited to:","opts":["Unlimited","A statutory portion of the bond","The full bond always","Nothing"],"correct":1,"re":"Employee wage/benefit claims may reach a defined portion of the bond."},
  {"id":363,"sec":"Org & Licensing","secNum":1,"block":4,"q":"A 'blank' contract signed by a consumer (terms filled in later) is:","opts":["Best practice","Prohibited — material terms must be present when signed","Required","Only for public works"],"correct":1,"re":"Consumers must not sign contracts with material terms left blank."},
  {"id":364,"sec":"Contracts","secNum":5,"block":4,"q":"A contractor's failure to include a required notice in a HIC can render the contract:","opts":["Stronger","Subject to challenge/unenforceable in part","Tax-free","Public"],"correct":1,"re":"Missing mandatory HIC notices can make the contract challengeable or partly unenforceable."},
  {"id":365,"sec":"Contracts","secNum":5,"block":4,"q":"A consumer's right to cancel a home-solicitation contract runs:","opts":["1 day","3 business days from signing/receipt of notice","30 days","Never"],"correct":1,"re":"The right to cancel is 3 business days from signing and receiving the notice."},
  {"id":366,"sec":"Contracts","secNum":5,"block":4,"q":"For certain senior citizens and disabled persons, the cancellation period may be:","opts":["Shorter","Extended beyond 3 days in defined situations","Removed","Tax-based"],"correct":1,"re":"Some statutes give specified seniors/disabled persons longer cancellation rights."},
  {"id":367,"sec":"Public Works","secNum":6,"block":4,"q":"A 'responsive' bid on public works is one that:","opts":["Is the lowest","Conforms to the bid requirements/specifications","Is from a local","Is unsigned"],"correct":1,"re":"Responsiveness means the bid conforms to the solicitation's requirements."},
  {"id":368,"sec":"Public Works","secNum":6,"block":4,"q":"A 'responsible' bidder is one that:","opts":["Bids lowest","Has the capacity, integrity, and reliability to perform","Is a corporation","Posts no bond"],"correct":1,"re":"Responsibility refers to the bidder's ability and trustworthiness to perform."},
  {"id":369,"sec":"Org & Licensing","secNum":1,"block":4,"q":"To act for a license, a 'bona fide employee' (for RME purposes) must be:","opts":["A figurehead","Permanently employed with actual supervisory duties","A part-time contractor","An owner only"],"correct":1,"re":"An RME must be a genuine, permanently employed person exercising real supervision."},
  {"id":370,"sec":"Org & Licensing","secNum":1,"block":4,"q":"A sham arrangement where the qualifier exercises no real control is:","opts":["Allowed","A violation (license available for improper use)","Common and legal","Tax-exempt"],"correct":1,"re":"A qualifier in name only, lacking real control, violates the license law."},
  {"id":371,"sec":"Safety","secNum":7,"block":4,"q":"A respirator's required medical evaluation must occur:","opts":["After a year of use","Before the employee is fit-tested and uses it","Only if requested","Never"],"correct":1,"re":"Medical clearance precedes fit testing and respirator use."},
  {"id":372,"sec":"Safety","secNum":7,"block":4,"q":"A Cal/OSHA 'general' violation (vs. serious) is one that:","opts":["Could cause death","Has a direct/immediate relationship to safety but not serious-injury probability","Is willful","Is criminal"],"correct":1,"re":"A general violation relates to safety/health without a substantial probability of serious harm."},
  {"id":373,"sec":"Business Finances","secNum":2,"block":4,"q":"A 'fixed' overhead cost example is:","opts":["Job materials","Monthly office rent","Per-job subcontractor","Fuel per job"],"correct":1,"re":"Office rent is a fixed overhead cost regardless of job volume."},
  {"id":374,"sec":"Business Finances","secNum":2,"block":4,"q":"A 'variable' cost example is:","opts":["Insurance premium","Materials that rise with job volume","Office salary","License fee"],"correct":1,"re":"Materials vary directly with production/job volume."},
  {"id":375,"sec":"Employment","secNum":3,"block":4,"q":"An employer must provide a workplace free of recognized hazards under the:","opts":["UCC","General duty obligation (Cal/OSHA)","Tax code","Lien law"],"correct":1,"re":"The general duty requires a workplace free from recognized serious hazards."},
  {"id":376,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"An 'umbrella' liability policy provides:","opts":["Workers' comp","Excess limits above primary GL/auto policies","A bond","Health insurance"],"correct":1,"re":"Umbrella coverage adds excess limits over underlying liability policies."},
  {"id":377,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"'Completed operations' coverage protects against claims arising:","opts":["During the job only","After the work is finished, from that completed work","Only from autos","Only from theft"],"correct":1,"re":"Completed-operations covers liability from work after it's completed."},
  {"id":378,"sec":"Contracts","secNum":5,"block":4,"q":"A 'cost-plus with a guaranteed maximum price (GMP)' contract:","opts":["Has no ceiling","Reimburses costs plus fee but caps the total","Is lump-sum","Pays per unit"],"correct":1,"re":"A GMP cost-plus reimburses actual cost plus fee, but not above the cap."},
  {"id":379,"sec":"Contracts","secNum":5,"block":4,"q":"A 'unit price' contract is best when:","opts":["Quantities are unknown but unit rates are set","Everything is fixed","No measurements exist","Only for homes"],"correct":0,"re":"Unit-price contracts suit work where quantities vary but per-unit rates are agreed."},
  {"id":380,"sec":"Public Works","secNum":6,"block":4,"q":"Public agencies often require, before award, a bidder to submit a:","opts":["Lien","Bid bond or bid security","Tax return","Permit"],"correct":1,"re":"A bid bond/security accompanies the bid to guarantee the bidder will contract."},
  {"id":381,"sec":"Org & Licensing","secNum":1,"block":4,"q":"A contractor convicted of an offense may show 'rehabilitation' to the CSLB by:","opts":["Ignoring it","Evidence of time elapsed, restitution, and changed conduct","Paying the bond","Re-advertising"],"correct":1,"re":"CSLB weighs rehabilitation evidence: time, restitution, compliance, and conduct."},
  {"id":382,"sec":"Safety","secNum":7,"block":4,"q":"A 'qualified' (vs. competent) person under Cal/OSHA usually has:","opts":["No training","Recognized degree/certificate or extensive knowledge to solve problems in the subject","Only a license","A bond"],"correct":1,"re":"A qualified person has recognized expertise (degree/certificate/experience) for the specific subject."},
  {"id":383,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"To preserve a stop payment notice on a private job, the claimant generally must also have served:","opts":["A lien","A valid preliminary 20-day notice","A bond","A permit"],"correct":1,"re":"A timely preliminary notice underpins stop-payment-notice and lien rights for non-direct claimants."},
  {"id":384,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"A mechanics lien is generally NOT available against:","opts":["A private home","Public property (use a stop payment notice / bond instead)","A commercial building","A remodel"],"correct":1,"re":"Public property cannot be liened; remedies are the payment bond and stop payment notice."},
  {"id":385,"sec":"Contracts","secNum":5,"block":4,"q":"A 'rescission' of a contract aims to:","opts":["Add scope","Unwind the contract and restore parties to their prior positions","Increase price","Extend time"],"correct":1,"re":"Rescission cancels the contract and seeks to return parties to the status quo ante."},
  {"id":386,"sec":"Contracts","secNum":5,"block":4,"q":"'Specific performance' is a remedy that:","opts":["Pays money only","Compels a party to perform the contract as agreed","Cancels the deal","Adds a bond"],"correct":1,"re":"Specific performance orders actual performance when money damages are inadequate."},
  {"id":387,"sec":"Business Finances","secNum":2,"block":4,"q":"A contractor's profit-and-loss statement for the year shows revenue $800k, COGS $560k, overhead $180k. Net profit is:","opts":["$60,000","$240,000","$120,000","$20,000"],"correct":0,"re":"$800k − $560k = $240k gross; $240k − $180k overhead = $60k net."},
  {"id":388,"sec":"Employment","secNum":3,"block":4,"q":"An employer must keep a record of hours worked for non-exempt employees because:","opts":["It's optional","Wage law requires accurate time records","Only for taxes","CSLB requires it"],"correct":1,"re":"Accurate time records are required to comply with wage-and-hour law."},
  {"id":389,"sec":"Employment","secNum":3,"block":4,"q":"Paying a 'piece rate' worker still requires:","opts":["No minimum","At least minimum wage for all hours and separate pay for rest/recovery time","Only piece pay","No breaks"],"correct":1,"re":"Piece-rate workers must still earn at least minimum wage and be paid for rest/recovery periods."},
  {"id":390,"sec":"Safety","secNum":7,"block":4,"q":"A fall-protection system at heights includes:","opts":["Only signs","Guardrails, personal fall arrest, or safety nets as appropriate","Just gloves","Nothing under 30 ft"],"correct":1,"re":"Acceptable systems include guardrails, PFAS, or nets depending on the task."},
  {"id":391,"sec":"Org & Licensing","secNum":1,"block":4,"q":"A license issued to a corporation is tied to:","opts":["Any officer","That specific corporate entity and its qualifier","The lender","The city"],"correct":1,"re":"The license belongs to the specific entity; it cannot be used by a different entity."},
  {"id":392,"sec":"Org & Licensing","secNum":1,"block":4,"q":"Selling or transferring a contractor's license number to another is:","opts":["Allowed with a fee","Prohibited — licenses are not transferable","Common","Encouraged"],"correct":1,"re":"Contractor licenses are not transferable or sellable."},
  {"id":393,"sec":"Public Works","secNum":6,"block":4,"q":"Apprentices on public works must be paid:","opts":["Nothing","The applicable apprentice prevailing wage rate for their level","Journeyman rate always","Minimum wage only"],"correct":1,"re":"Apprentices receive the prevailing apprentice rate corresponding to their progression."},
  {"id":394,"sec":"Business Finances","secNum":2,"block":4,"q":"A contractor's 'gross margin %' on a job that cost $7,000 and sold for $10,000 is:","opts":["20%","30%","43%","70%"],"correct":1,"re":"Margin = (10,000 − 7,000)/10,000 = 30%."},
  {"id":395,"sec":"Contracts","secNum":5,"block":4,"q":"A signed proposal that contains all essential terms and is accepted becomes:","opts":["A lien","A binding contract","A permit","A bond"],"correct":1,"re":"Acceptance of a complete offer forms a binding contract."},
  {"id":396,"sec":"Safety","secNum":7,"block":4,"q":"The best first step when an unknown material may contain asbestos is to:","opts":["Demolish it","Stop and have it sampled/tested by a qualified party","Burn it","Paint over it"],"correct":1,"re":"Suspect ACM should be tested before disturbance; assume hazard until cleared."},
  {"id":397,"sec":"Insurance & Liens","secNum":4,"block":4,"q":"A 'release of lien' should be obtained from subs/suppliers to:","opts":["Raise the price","Confirm they've been paid and won't lien the property","Cancel the permit","Avoid taxes"],"correct":1,"re":"Lien releases document payment and protect the owner/prime from later liens."},
  {"id":398,"sec":"Org & Licensing","secNum":1,"block":4,"q":"A contractor who lets their license lapse and keeps working is:","opts":["Fine","Operating unlicensed and exposed to §7031 and discipline","Protected","Exempt"],"correct":1,"re":"Working on an expired license is unlicensed activity with §7031 and disciplinary exposure."},
  {"id":399,"sec":"Employment","secNum":3,"block":4,"q":"An IIPP must include all of the following EXCEPT:","opts":["Hazard identification and correction","Training and communication","A responsible person","A marketing budget"],"correct":3,"re":"IIPP elements include responsibility, hazard ID/correction, training, and communication — not marketing."},
  {"id":400,"sec":"Org & Licensing","secNum":1,"block":4,"q":"The single best way to avoid CSLB discipline is to:","opts":["Avoid contracts","Follow the license law, finish work, and communicate/resolve issues promptly","Never carry a bond","Work unlicensed"],"correct":1,"re":"Compliance, completing work, and prompt issue resolution prevent most disciplinary problems."},
  {"id":401,"sec":"Org & Licensing","secNum":1,"block":5,"q":"All of the following can qualify a contractor's license EXCEPT a(n):","opts":["RMO (owner)","RME (employee)","Sole owner applicant","Unrelated unlicensed friend"],"correct":3,"re":"Only a qualified RMO, RME, or qualifying sole owner can qualify a license — not an unrelated unlicensed person."},
  {"id":402,"sec":"Org & Licensing","secNum":1,"block":5,"q":"Which is LEAST likely to require a CSLB license?","opts":["A $5,000 HVAC install","A $1,200 repair with a permit","A $300 single-trade repair, no permit, no employees","A $50,000 remodel"],"correct":2,"re":"Work under the threshold, single-trade, no permit/employees, is least likely to require a license."},
  {"id":403,"sec":"Business Finances","secNum":2,"block":5,"q":"A company with $50,000 current assets and $20,000 current liabilities has a current ratio of:","opts":["0.4","1.5","2.5","5.0"],"correct":2,"re":"50,000 ÷ 20,000 = 2.5."},
  {"id":404,"sec":"Business Finances","secNum":2,"block":5,"q":"If you want a 25% gross margin on a job that costs $9,000, you must charge:","opts":["$11,250","$12,000","$11,000","$10,800"],"correct":1,"re":"Price = cost ÷ (1 − margin) = 9,000 ÷ 0.75 = $12,000."},
  {"id":405,"sec":"Employment","secNum":3,"block":5,"q":"An employee works 10 hours Monday. Overtime hours owed at 1.5× are:","opts":["0","1","2","10"],"correct":2,"re":"Hours 9 and 10 (over 8/day) are paid at 1.5× — that's 2 OT hours."},
  {"id":406,"sec":"Employment","secNum":3,"block":5,"q":"An employee works 13 hours in one day. Double-time hours owed are:","opts":["0","1","4","5"],"correct":1,"re":"Over 12 hours triggers 2×; only the 13th hour is double time (hours 9–12 are 1.5×)."},
  {"id":407,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"With NO Notice of Completion recorded, ALL claimants have how long after completion to record a lien?","opts":["30 days","60 days","90 days","6 months"],"correct":2,"re":"Without an NOC, everyone has 90 days after completion."},
  {"id":408,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"A preliminary notice served 35 days after first furnishing materials protects lien rights:","opts":["For all amounts","Only for materials furnished within 20 days before the notice and after","For nothing","For double the amount"],"correct":1,"re":"A late preliminary notice protects only amounts within 20 days before service and afterward."},
  {"id":409,"sec":"Contracts","secNum":5,"block":5,"q":"A home improvement contract is signed for $40,000. The maximum lawful down payment is:","opts":["$4,000","$1,000","$10,000","$2,000"],"correct":1,"re":"Lesser of $1,000 or 10% ($4,000) = $1,000."},
  {"id":410,"sec":"Contracts","secNum":5,"block":5,"q":"On a $6,000 HVAC home-improvement job, the maximum down payment is:","opts":["$600","$1,000","$1,200","$3,000"],"correct":0,"re":"10% of $6,000 = $600, which is less than $1,000, so $600 is the cap."},
  {"id":411,"sec":"Public Works","secNum":6,"block":5,"q":"Prevailing wage on a $900 city repair is:","opts":["Required","Not required (under the $1,000 threshold)","Double","Optional"],"correct":1,"re":"Under the $1,000 threshold, prevailing wage generally doesn't apply."},
  {"id":412,"sec":"Safety","secNum":7,"block":5,"q":"All of the following are required Cal/OSHA programs/items EXCEPT:","opts":["Written IIPP","Heat illness prevention (outdoor)","Hazard Communication / SDS access","A profit-sharing plan"],"correct":3,"re":"Profit-sharing is not a safety requirement; the others are Cal/OSHA mandates."},
  {"id":413,"sec":"Org & Licensing","secNum":1,"block":5,"q":"A contractor changes from a sole proprietorship to an LLC. The correct action is to:","opts":["Keep the old license","Apply for a new license for the LLC","Just notify the bank","Do nothing"],"correct":1,"re":"A new legal entity requires its own license; the old one can't carry over."},
  {"id":414,"sec":"Org & Licensing","secNum":1,"block":5,"q":"An LLC contractor must maintain BOTH a $25,000 contractor bond and a:","opts":["$5,000 bond","$100,000 worker bond plus liability insurance","$1,000 deposit","Nothing extra"],"correct":1,"re":"LLCs need the $25k bond, a $100k worker bond, and liability insurance."},
  {"id":415,"sec":"Business Finances","secNum":2,"block":5,"q":"Which is NOT a current asset?","opts":["Cash","Accounts receivable","A 10-year work truck","Inventory"],"correct":2,"re":"A long-lived truck is a fixed asset, not a current asset."},
  {"id":416,"sec":"Business Finances","secNum":2,"block":5,"q":"Which is a long-term liability?","opts":["This month's payables","A 6-year equipment loan","Wages due Friday","A 30-day invoice"],"correct":1,"re":"A multi-year loan is a long-term liability."},
  {"id":417,"sec":"Employment","secNum":3,"block":5,"q":"An employee earns a $200 nondiscretionary bonus in a 40-hour week. For OT that week, the bonus:","opts":["Is ignored","Must be included in the regular rate","Doubles","Is taxed twice"],"correct":1,"re":"Nondiscretionary bonuses raise the regular rate used to compute overtime."},
  {"id":418,"sec":"Employment","secNum":3,"block":5,"q":"A worker quits with no notice on Tuesday. Final pay is due:","opts":["Immediately","Within 72 hours","Next payday","In 30 days"],"correct":1,"re":"Quit without notice: final wages within 72 hours."},
  {"id":419,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"A contractor wants a recorded lien removed quickly to clear title. The owner can:","opts":["Wait it out","Record a lien release bond (125% of the lien)","Sue the lender","Cancel the permit"],"correct":1,"re":"A 125% release bond substitutes for the property, clearing title."},
  {"id":420,"sec":"Contracts","secNum":5,"block":5,"q":"A change order should be executed:","opts":["Verbally, later","In writing and signed BEFORE the changed work proceeds","After the job","Only if over $10,000"],"correct":1,"re":"Get change orders in writing and signed before doing the extra work."},
  {"id":421,"sec":"Public Works","secNum":6,"block":5,"q":"On a public works job, the contractor must register apprentices and submit certified payroll. Failing to do so risks:","opts":["Nothing","Penalties, withheld payments, and debarment","A bonus","Faster payment"],"correct":1,"re":"Noncompliance risks penalties, withheld funds, and debarment."},
  {"id":422,"sec":"Safety","secNum":7,"block":5,"q":"At 96°F outdoors, the employer's heat duties include all EXCEPT:","opts":["Water","Shade","High-heat procedures","Issuing stock options"],"correct":3,"re":"Stock options aren't a heat-standard duty; water, shade, and high-heat procedures are."},
  {"id":423,"sec":"Org & Licensing","secNum":1,"block":5,"q":"Advertising as a licensed contractor without a current license is:","opts":["Allowed","A violation","Only an online issue","Encouraged"],"correct":1,"re":"Holding yourself out as licensed without a valid license is a violation."},
  {"id":424,"sec":"Org & Licensing","secNum":1,"block":5,"q":"To take the trade exam for C-20, the applicant generally needs about how many years of journey-level experience?","opts":["1","2","4","8"],"correct":2,"re":"Four years of qualifying experience within the past 10 is the general requirement."},
  {"id":425,"sec":"Business Finances","secNum":2,"block":5,"q":"Overhead recovery in a bid is achieved by:","opts":["Ignoring overhead","Adding a markup/allocation to job costs to cover overhead and profit","Lowering price","Skipping insurance"],"correct":1,"re":"Bids must include markup that recovers overhead and target profit."},
  {"id":426,"sec":"Employment","secNum":3,"block":5,"q":"A licensed sub you hire who runs their own crew is, for your payroll:","opts":["Your employee","Not your employee","An apprentice","A partner"],"correct":1,"re":"A genuine licensed sub with their own workers isn't your payroll employee."},
  {"id":427,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"Which is TRUE about a mechanics lien on a public school project?","opts":["It attaches to the school","It is not available; use a stop payment notice/payment bond","It doubles","It needs no notice"],"correct":1,"re":"Public property can't be liened; use the stop payment notice and payment bond."},
  {"id":428,"sec":"Contracts","secNum":5,"block":5,"q":"A contract missing a lawful object (e.g., unlicensed required work) is:","opts":["Enforceable","Void","Voidable only","Express"],"correct":1,"re":"A contract for an unlawful object is void."},
  {"id":429,"sec":"Contracts","secNum":5,"block":5,"q":"Which is NOT required for a valid contract?","opts":["Mutual consent","Consideration","Lawful object","A profit guarantee"],"correct":3,"re":"No 'profit guarantee' is needed; consent, consideration, capacity, and lawful object are."},
  {"id":430,"sec":"Public Works","secNum":6,"block":5,"q":"A bid is submitted with a $5,000 math error in the contractor's favor's opposite (too low). The contractor may:","opts":["Never withdraw","Seek to withdraw/rescind promptly if the mistake is material and meets conditions","Double the price after award","Ignore it"],"correct":1,"re":"A genuine, material clerical bid mistake, raised promptly, may allow rescission."},
  {"id":431,"sec":"Safety","secNum":7,"block":5,"q":"Before entering an attic to service equipment, the technician should consider:","opts":["Nothing","Heat, confined-space, and fall/footing hazards","Only the price","Only the bond"],"correct":1,"re":"Attics pose heat, confined-space, and fall hazards to assess first."},
  {"id":432,"sec":"Org & Licensing","secNum":1,"block":5,"q":"A contractor's license number must appear on all of the following EXCEPT:","opts":["Business cards/ads","Contracts","Bid proposals","A personal birthday card"],"correct":3,"re":"The number belongs on advertising, contracts, and proposals — not on unrelated personal items."},
  {"id":433,"sec":"Business Finances","secNum":2,"block":5,"q":"A negative working capital means current liabilities:","opts":["Are zero","Exceed current assets (liquidity risk)","Equal assets","Are tax-free"],"correct":1,"re":"Negative working capital = current liabilities exceed current assets."},
  {"id":434,"sec":"Employment","secNum":3,"block":5,"q":"Which worker is most clearly an EMPLOYEE?","opts":["A licensed sub with own crew","A hourly helper you direct and supply tools for","A material vendor","A separate firm you subcontract"],"correct":1,"re":"An hourly, directed worker using your tools is an employee."},
  {"id":435,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"A performance bond and a payment bond together protect:","opts":["Only the contractor","Project completion AND payment to subs/suppliers","Only the lender","Only the city"],"correct":1,"re":"Performance secures completion; payment secures subs/suppliers."},
  {"id":436,"sec":"Contracts","secNum":5,"block":5,"q":"A consumer signs at their home after a door-to-door pitch. They may cancel within:","opts":["24 hours","3 business days","30 days","Never"],"correct":1,"re":"Home-solicitation sales carry a 3-business-day cancellation right."},
  {"id":437,"sec":"Public Works","secNum":6,"block":5,"q":"Certified payroll exists primarily to:","opts":["Set the bid","Prove prevailing wage and apprenticeship compliance","Reduce taxes","Avoid permits"],"correct":1,"re":"Certified payroll documents prevailing-wage and apprenticeship compliance."},
  {"id":438,"sec":"Safety","secNum":7,"block":5,"q":"The MOST important document for Cal/OSHA compliance at a small contractor is the:","opts":["Bond","Written IIPP","Bid sheet","Lien log"],"correct":1,"re":"The written IIPP is the foundation of Cal/OSHA compliance."},
  {"id":439,"sec":"Org & Licensing","secNum":1,"block":5,"q":"A contractor disciplined and seeking a new license after revocation must usually wait at least:","opts":["1 week","1 year","Never allowed","10 years always"],"correct":1,"re":"Reapplication after revocation is generally barred for at least one year."},
  {"id":440,"sec":"Business Finances","secNum":2,"block":5,"q":"A contractor's bid should include a contingency to:","opts":["Increase taxes","Buffer unforeseen costs/risk","Lower the price","Skip insurance"],"correct":1,"re":"A contingency cushions against unknowns and risk."},
  {"id":441,"sec":"Employment","secNum":3,"block":5,"q":"An employer fails to provide a duty-free meal break for a 6-hour shift. The employee is owed:","opts":["Nothing","One hour of premium pay","A written apology","Double time"],"correct":1,"re":"A missed meal period owes one premium hour at the regular rate."},
  {"id":442,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"A subcontractor who served a valid preliminary notice and went unpaid should next:","opts":["Quit the trade","Record a mechanics lien within the deadline (and/or serve a stop payment notice)","Call the police","Do nothing"],"correct":1,"re":"With a valid preliminary notice, record a timely lien and/or serve a stop payment notice."},
  {"id":443,"sec":"Contracts","secNum":5,"block":5,"q":"If a written contract and an oral side promise conflict (with an integration clause), generally:","opts":["The oral wins","The written contract controls","Both void","The lien controls"],"correct":1,"re":"With integration, the writing controls over prior oral terms."},
  {"id":444,"sec":"Public Works","secNum":6,"block":5,"q":"To bid a $2,000,000 school HVAC project, a C-20 contractor must, among other things:","opts":["Nothing special","Be DIR-registered, pay prevailing wage, and meet apprenticeship/skilled-workforce rules","Only carry a bond","Avoid certified payroll"],"correct":1,"re":"Public works require DIR registration, prevailing wage, certified payroll, and workforce rules."},
  {"id":445,"sec":"Safety","secNum":7,"block":5,"q":"A worker must be reported to Cal/OSHA within 8 hours for:","opts":["A minor cut","A fatality, amputation, or in-patient hospitalization","A late arrival","A parking issue"],"correct":1,"re":"Serious outcomes (death, amputation, hospitalization) require 8-hour reporting."},
  {"id":446,"sec":"Org & Licensing","secNum":1,"block":5,"q":"Which action does NOT require notifying the CSLB?","opts":["Change of business address","Disassociation of the qualifier","Change of business entity","Buying a new work van"],"correct":3,"re":"Buying a van isn't a CSLB-reportable change; address, qualifier, and entity changes are."},
  {"id":447,"sec":"Business Finances","secNum":2,"block":5,"q":"A 'break-even analysis' helps a contractor determine:","opts":["The bond","Sales needed to cover all costs","The permit fee","The lien amount"],"correct":1,"re":"Break-even shows the sales volume where revenue equals total cost."},
  {"id":448,"sec":"Employment","secNum":3,"block":5,"q":"Cash payroll 'under the table' most directly violates:","opts":["Building code","Payroll tax and labor law (and risks fraud charges)","Lien law","Title 24"],"correct":1,"re":"Off-the-books pay evades payroll taxes and labor law and can be criminal."},
  {"id":449,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"Which is the correct lien sequence (no NOC)?","opts":["Lien → preliminary notice → suit","Preliminary 20-day notice → record lien within 90 days → foreclosure suit within 90 days","Suit → lien → notice","Notice → suit → lien"],"correct":1,"re":"Serve preliminary notice, record the lien within 90 days, then sue within 90 days of recording."},
  {"id":450,"sec":"Contracts","secNum":5,"block":5,"q":"A contractor who takes a deposit and never starts the work may be liable for:","opts":["Nothing","Abandonment/diversion — discipline plus refund/damages","A bonus","A tax credit"],"correct":1,"re":"Taking money and abandoning is disciplinable and exposes the contractor to refunds/damages."},
  {"id":451,"sec":"Public Works","secNum":6,"block":5,"q":"A 'change order' on a public works contract generally must be:","opts":["Verbal","Written and approved per the contract/agency procedures","Ignored","Hidden"],"correct":1,"re":"Public contracts require written, approved change orders following agency procedures."},
  {"id":452,"sec":"Safety","secNum":7,"block":5,"q":"PPE must be provided by the employer:","opts":["At employee cost","At no cost to the employee when required","Only on public works","Never"],"correct":1,"re":"Required PPE is employer-provided at no cost to workers."},
  {"id":453,"sec":"Org & Licensing","secNum":1,"block":5,"q":"A 'qualifying individual' who owns at least 10% of the corporation is typically a(n):","opts":["RME","RMO","Apprentice","Bondholder"],"correct":1,"re":"An owner-qualifier (10%+) is the RMO; an employee-qualifier is the RME."},
  {"id":454,"sec":"Business Finances","secNum":2,"block":5,"q":"A company's net worth equals:","opts":["Cash on hand","Total assets minus total liabilities","Annual revenue","Markup"],"correct":1,"re":"Net worth (equity) = assets − liabilities."},
  {"id":455,"sec":"Employment","secNum":3,"block":5,"q":"Which is an employer-paid payroll tax (not withheld from the worker)?","opts":["Employee income tax","FUTA/SUI unemployment tax","SDI","The worker's FICA share"],"correct":1,"re":"Unemployment taxes are employer-paid; income tax, SDI, and the employee FICA share are withheld."},
  {"id":456,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"A 'conditional waiver and release on final payment' takes effect:","opts":["On signing","When the final payment actually clears","Never","After 90 days"],"correct":1,"re":"Conditional final waivers are effective only once the final payment is received/clears."},
  {"id":457,"sec":"Contracts","secNum":5,"block":5,"q":"A liquidated-damages clause of $500/day for a 10-day delay yields:","opts":["$500","$5,000","$50","$10,000"],"correct":1,"re":"$500 × 10 = $5,000."},
  {"id":458,"sec":"Public Works","secNum":6,"block":5,"q":"On public works over $25,000, the contractor generally must provide a:","opts":["Lien","Payment bond","Title 24 form","Marketing plan"],"correct":1,"re":"Public works payment bonds are required when the contract exceeds $25,000."},
  {"id":459,"sec":"Safety","secNum":7,"block":5,"q":"The 4:1 ladder rule means for a 16-foot working height, the base is out:","opts":["1 foot","2 feet","4 feet","8 feet"],"correct":2,"re":"16 ÷ 4 = 4 feet of base offset."},
  {"id":460,"sec":"Org & Licensing","secNum":1,"block":5,"q":"A contractor's bond claim window is generally limited; claims must be filed within:","opts":["No limit","A statutory period (commonly within a few years of the act)","10 days","Forever"],"correct":1,"re":"Bond claims are subject to statutory time limits; file promptly."},
  {"id":461,"sec":"Business Finances","secNum":2,"block":5,"q":"If overhead is 18% of sales and net profit target is 8%, total markup over job cost must cover:","opts":["8%","18%","26% (overhead + profit) of sales","0%"],"correct":2,"re":"Pricing must cover overhead (18%) plus profit (8%) = 26% of sales above direct cost."},
  {"id":462,"sec":"Employment","secNum":3,"block":5,"q":"A non-exempt employee works 45 hours in a week (9/day × 5). OT hours that week total:","opts":["0","5","8","10"],"correct":1,"re":"Each day has 1 OT hour (9th); 5 days = 5 OT hours at 1.5×."},
  {"id":463,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"A material supplier with no direct owner contract preserves lien rights mainly by:","opts":["Recording first","Serving a timely preliminary 20-day notice","Calling the owner","Filing taxes"],"correct":1,"re":"The 20-day preliminary notice preserves a remote supplier's lien rights."},
  {"id":464,"sec":"Contracts","secNum":5,"block":5,"q":"A contract clause requiring all disputes to be decided by a neutral with a binding award is:","opts":["Mediation","Binding arbitration","Estoppel","A lien"],"correct":1,"re":"That describes binding arbitration."},
  {"id":465,"sec":"Public Works","secNum":6,"block":5,"q":"A contractor underpays prevailing wages, then 'tops up' after an audit. They still face:","opts":["Nothing","Penalties and possible debarment","A refund","A bonus"],"correct":1,"re":"Restitution doesn't erase penalties and debarment exposure for the underpayment."},
  {"id":466,"sec":"Safety","secNum":7,"block":5,"q":"Which is the BEST response to suspected asbestos during a furnace removal?","opts":["Remove it fast","Stop, isolate, and have it tested by a qualified party","Wet it and bag it yourself","Ignore it"],"correct":1,"re":"Stop work and test suspect ACM before disturbing it."},
  {"id":467,"sec":"Org & Licensing","secNum":1,"block":5,"q":"Aiding an unlicensed person to contract, then taking a cut, is:","opts":["Smart business","A license-law violation (aiding unlicensed activity)","Legal under $5,000","Encouraged"],"correct":1,"re":"Helping unlicensed contracting for a cut violates the license law."},
  {"id":468,"sec":"Business Finances","secNum":2,"block":5,"q":"Job costing reveals a project lost money. The MOST useful next step is to:","opts":["Hide it","Analyze estimate vs. actuals to fix future bidding","Stop job costing","Raise the bond"],"correct":1,"re":"Compare estimated vs. actual costs to correct estimating and prevent repeat losses."},
  {"id":469,"sec":"Employment","secNum":3,"block":5,"q":"Which is TRUE about workers' comp for a sole owner with no employees?","opts":["Always required","May file an exemption (no employees)","Illegal to skip","Paid by the client"],"correct":1,"re":"A sole owner with no employees can certify a WC exemption."},
  {"id":470,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"An additional-insured endorsement on a sub's policy typically benefits the:","opts":["Sub only","General contractor/owner named as additional insured","Lender only","City"],"correct":1,"re":"It extends the sub's coverage to the GC/owner as additional insured."},
  {"id":471,"sec":"Contracts","secNum":5,"block":5,"q":"A contractor wants to limit liability for delays caused by weather. The best tool is a:","opts":["Lien","Force majeure / excusable-delay clause","Bond","Permit"],"correct":1,"re":"A force majeure/excusable-delay clause addresses delays beyond the contractor's control."},
  {"id":472,"sec":"Public Works","secNum":6,"block":5,"q":"The lowest bid is non-conforming (missing a required bond). The agency should:","opts":["Award it anyway","Treat it as non-responsive and may reject it","Double it","Ignore the rules"],"correct":1,"re":"A bid missing required elements is non-responsive and may be rejected."},
  {"id":473,"sec":"Safety","secNum":7,"block":5,"q":"A confined space with a hazardous atmosphere requires, before entry:","opts":["Nothing","Atmospheric testing, ventilation/controls, and a permit/program","Just a flashlight","A bond"],"correct":1,"re":"Permit-required confined spaces need testing, controls, and an entry program."},
  {"id":474,"sec":"Org & Licensing","secNum":1,"block":5,"q":"All new CSLB license applicants must complete the:","opts":["Asbestos open-book exam","C-22 certification","HAZ exam","Real estate course"],"correct":0,"re":"Every new applicant must pass the asbestos open-book exam before licensure."},
  {"id":475,"sec":"Business Finances","secNum":2,"block":5,"q":"A contractor's bonding capacity will MOST improve by:","opts":["Buying trucks on credit","Increasing working capital and net worth, and a clean track record","Lowering prices","Skipping insurance"],"correct":1,"re":"Stronger working capital, net worth, and history raise bonding capacity."},
  {"id":476,"sec":"Employment","secNum":3,"block":5,"q":"An employer that classifies real employees as 1099 to dodge taxes/WC risks:","opts":["Nothing","Back taxes, penalties, WC liability, and possible criminal charges","A refund","A bonus"],"correct":1,"re":"Willful misclassification brings back taxes, penalties, WC liability, and possibly crimes."},
  {"id":477,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"The contractor's $25,000 bond is intended to compensate for harm from:","opts":["Any business loss","Specified violations affecting consumers, employees, and certain others","Bad weather","Material price spikes"],"correct":1,"re":"The bond covers statutory violations harming homeowners, employees, and certain others."},
  {"id":478,"sec":"Contracts","secNum":5,"block":5,"q":"A HIC must NOT:","opts":["State the price","Provide a work-based payment schedule","Require a down payment over the legal cap","Include cancellation notice"],"correct":2,"re":"Exceeding the lawful down-payment cap is prohibited."},
  {"id":479,"sec":"Public Works","secNum":6,"block":5,"q":"A contractor on public works must keep DIR registration:","opts":["Expired is fine","Current and renewed on schedule","Only for the first job","Optional"],"correct":1,"re":"DIR registration must remain current to bid/perform public works."},
  {"id":480,"sec":"Safety","secNum":7,"block":5,"q":"A new employee should receive safety training:","opts":["After a year","Before/at the start of work for their assigned tasks","Only if injured","Never"],"correct":1,"re":"Train workers on hazards before or as they begin assigned work."},
  {"id":481,"sec":"Org & Licensing","secNum":1,"block":5,"q":"If a contractor's qualifier dies, the business should:","opts":["Keep operating indefinitely","Promptly notify CSLB and replace the qualifier within the allowed time","Hide it","Sell the license"],"correct":1,"re":"Notify CSLB and replace the qualifier within the statutory window to avoid suspension."},
  {"id":482,"sec":"Business Finances","secNum":2,"block":5,"q":"A 'markup' of 20% on $5,000 cost gives a price of:","opts":["$5,200","$6,000","$6,250","$1,000"],"correct":1,"re":"$5,000 × 1.20 = $6,000."},
  {"id":483,"sec":"Employment","secNum":3,"block":5,"q":"A worker on the 7th straight day works 9 hours. Pay is:","opts":["All straight time","8 hours at 1.5× and the 9th hour at 2×","All double time","No premium"],"correct":1,"re":"7th-day: first 8 hours at 1.5×, beyond 8 at 2×."},
  {"id":484,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"The remedy on a FEDERAL public project for unpaid subs is the:","opts":["State lien","Miller Act payment bond","Title 24","CSLB bond"],"correct":1,"re":"Federal projects use the Miller Act payment bond."},
  {"id":485,"sec":"Contracts","secNum":5,"block":5,"q":"A contractor substantially completes a kitchen but a cabinet door is misaligned. The owner generally owes:","opts":["Nothing","The price minus the cost to fix the minor item","Double","Only the down payment"],"correct":1,"re":"Substantial performance: price less the cost to correct minor punch-list items."},
  {"id":486,"sec":"Public Works","secNum":6,"block":5,"q":"Submitting falsified certified payroll is:","opts":["A minor error","Fraud — penalties, debarment, and criminal exposure","Standard","Encouraged"],"correct":1,"re":"Falsified certified payroll is serious fraud with severe consequences."},
  {"id":487,"sec":"Safety","secNum":7,"block":5,"q":"To service energized rooftop equipment safely, FIRST:","opts":["Start working","De-energize and apply lockout/tagout","Remove guards","Skip PPE"],"correct":1,"re":"De-energize and apply LOTO before servicing."},
  {"id":488,"sec":"Org & Licensing","secNum":1,"block":5,"q":"A C-20 contractor wants to also do electrical panel work. They should:","opts":["Just do it","Hold/obtain the proper classification (e.g., C-10) or use a licensed C-10 sub","Skip the permit","Advertise it anyway"],"correct":1,"re":"Electrical work needs the C-10 classification or a licensed C-10 subcontractor."},
  {"id":489,"sec":"Business Finances","secNum":2,"block":5,"q":"A contractor's quick ratio is 0.7. This suggests:","opts":["Strong liquidity","Possible difficulty covering short-term debts without selling inventory","No risk","High profit"],"correct":1,"re":"A quick ratio below 1 hints at tight short-term liquidity."},
  {"id":490,"sec":"Employment","secNum":3,"block":5,"q":"A contractor must provide an itemized wage statement:","opts":["Yearly","Each pay period","Only on request","Never"],"correct":1,"re":"An itemized pay stub is required every pay period."},
  {"id":491,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"Which of these is TRUE about preliminary notices?","opts":["Only owners send them","Many claimants must serve them within 20 days of first furnishing to preserve rights","They replace liens","They are never required"],"correct":1,"re":"Non-direct claimants generally must serve a 20-day preliminary notice."},
  {"id":492,"sec":"Contracts","secNum":5,"block":5,"q":"An 'as-is' clause in a contract attempts to:","opts":["Add a warranty","Limit warranties on the condition delivered","Increase price","Add a bond"],"correct":1,"re":"'As-is' tries to limit implied warranties on the delivered condition."},
  {"id":493,"sec":"Public Works","secNum":6,"block":5,"q":"On public works, apprentices must be employed at not less than a:","opts":["1:1 ratio","1:5 (apprentice:journeyman) ratio","1:10 ratio","0 ratio"],"correct":1,"re":"At least 1 apprentice hour per 5 journeyman hours is generally required."},
  {"id":494,"sec":"Safety","secNum":7,"block":5,"q":"The annual Cal/OSHA 300A summary is posted from February 1 to:","opts":["March 1","April 30","June 30","December 31"],"correct":1,"re":"Post the 300A from February 1 through April 30."},
  {"id":495,"sec":"Org & Licensing","secNum":1,"block":5,"q":"A contractor's advertising claiming a classification they don't hold is:","opts":["Allowed","A violation","Smart","Required"],"correct":1,"re":"Advertising an unheld classification is a license-law violation."},
  {"id":496,"sec":"Business Finances","secNum":2,"block":5,"q":"To price a job to net 10% profit after 25% overhead on a $10,000 direct cost, you'd add roughly:","opts":["$1,000","$3,500 (overhead + profit on cost)","$500","$0"],"correct":1,"re":"Overhead 25% ($2,500) + profit ~10% target (~$1,000+) ≈ $3,500 markup over the $10,000 cost (approx)."},
  {"id":497,"sec":"Employment","secNum":3,"block":5,"q":"An employer must report a new hire to the EDD within:","opts":["20 days","60 days","90 days","1 year"],"correct":0,"re":"New hires are reported to the EDD within 20 days."},
  {"id":498,"sec":"Insurance & Liens","secNum":4,"block":5,"q":"A lien recorded but never foreclosed within 90 days:","opts":["Stays forever","Becomes unenforceable and should be released","Doubles","Converts to a bond"],"correct":1,"re":"No timely foreclosure suit means the lien is unenforceable and must be released."},
  {"id":499,"sec":"Contracts","secNum":5,"block":5,"q":"The strongest protection against a payment dispute is:","opts":["A handshake","A clear written contract with scope, price, schedule, and change-order terms","A bigger down payment","A larger bond"],"correct":1,"re":"A complete written contract is the best defense against payment disputes."},
  {"id":500,"sec":"Org & Licensing","secNum":1,"block":5,"q":"The overarching purpose of the Contractors State License Law is to:","opts":["Maximize fees","Protect the public and ensure competent, honest contracting","Limit competition","Raise taxes"],"correct":1,"re":"The license law exists to protect the public through competent, honest contracting."}
];
